import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EProgressBarColor, EProgressBarMode, ProgressBarComponent } from '../../atoms/progress-bar/progress-bar.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode } from '../../buttons/button/button.component';
import { ETextButtonMode, ETextButtonType, TextButtonComponent } from '../../buttons/text-button/text-button.component';

export interface ITasksPanelTask {
	id: string;
	type?: ETasksPanelTaskType;
	image?: string;
	icon?: EIconName;
	title: string;
	description?: string;
	closeTaskButtonTooltip?: string;
	link?: string;
	progressBarValue?: number;
	state?: ETasksPanelTaskState;
}

export enum ETasksPanelTaskType {
  ELEARNING = 'elearning',
  IMAGE = 'image',
  AUDIO = 'audio',
  DOC = 'doc',
  PDF = 'PDF',
  ZIP = 'ZIP',
  VIDEO = 'video',
	ERROR = 'error'
}

export enum ETasksPanelMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum ETasksPanelTaskState {
  PENDING = 'pending',
  DONE = 'done'
}

@Component({
  selector: 'admin-tasks-panel',
  standalone: true,
  imports: [
		CommonModule,
		ButtonComponent,
		IconComponent,
		TextButtonComponent,
		ProgressBarComponent,
	],
  templateUrl: './tasks-panel.component.html',
  styleUrl: './tasks-panel.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class TasksPanelComponent {
	@Input() mode = ETasksPanelMode.LIGHT;
	@Input() title: string = '';
	@Input() closePanelButtonTooltip = '';
	@Input() stopTasksButtonTooltip = '';
	@Input() hasStopTaskButton: boolean = true;
	@Input() tasks: ITasksPanelTask[] = [];
	@Input() type!: ETasksPanelTaskType;
	@Input() showSkeleton: boolean = false;
	@Input() skeletonItems: number = 1;

	icon!:string;
	cardIconFontFamily!:string;

	@Output() stopTasksButtonClicked = new EventEmitter<void>();
	@Output() closePanelButtonClicked = new EventEmitter<void>();
	@Output() closeTaskButtonClicked = new EventEmitter<string>();
	@Output() openTaskButtonClicked = new EventEmitter<string>();

	ETasksPanelMode = ETasksPanelMode;
	EButtonMode = EButtonMode;
	EButtonButtonType = EButtonButtonType;
	EButtonColor = EButtonColor;
	EIconName = EIconName;
	ETextButtonMode = ETextButtonMode;
	ETextButtonType = ETextButtonType;
	EProgressBarMode = EProgressBarMode;
	EProgressBarColor = EProgressBarColor;
	ETasksPanelTaskState = ETasksPanelTaskState;

	typeOptions = [
    { 
      type: ETasksPanelTaskType.ELEARNING,
      icon: EIconName.SCHOOL,
    },
    { 
      type: ETasksPanelTaskType.IMAGE, 
      icon: EIconName.IMAGE,
    },
    { 
      type: ETasksPanelTaskType.AUDIO, 
      icon: EIconName.HEADPHONES,
    },
    { 
      type: ETasksPanelTaskType.DOC, 
      icon: EIconName.DESCRIPTION,
    },
    { 
      type: ETasksPanelTaskType.PDF, 
      icon: EIconName.CUSTOM_PDF,
    },
    { 
      type: ETasksPanelTaskType.ZIP,
      icon: EIconName.FOLDER_ZIP,
    },
    { 
      type: ETasksPanelTaskType.VIDEO, 
      icon: EIconName.ONDEMAND_VIDEO,
    },
    { 
      type: ETasksPanelTaskType.ERROR, 
      icon: EIconName.CLOSE,
    },
  ];

	getTaskIcon(task: ITasksPanelTask): EIconName {
		if (task.icon) {
			return task.icon;
		}
		if (task.type) {
			const typeDetail = this.typeOptions.find(option => option.type === task.type);
			return typeDetail ? typeDetail.icon : EIconName.BROKEN_IMAGE;
		}
		return EIconName.BROKEN_IMAGE;
	}

	oncloseTaskButtonClicked(id: string) {
		this.closeTaskButtonClicked.emit(id);
	}

	onOpenTaskButtonClicked(id: string) {
		this.openTaskButtonClicked.emit(id);
	}

}
