import { AfterViewInit, Component, EventEmitter, Input, Output, QueryList, ViewChild, ViewChildren, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatSidenav, MatSidenavModule } from '@angular/material/sidenav';
import { tap } from 'rxjs';
import { filter } from 'rxjs/operators';
import { PanelComponent } from '../../layout/panel/panel.component';
import { SidenavService } from './services/sidenav.service';

export enum EGlobalPanelMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-global-panel',
	standalone: true,
	imports: [
		MatIconModule,
		MatSidenavModule
	],
	templateUrl: './global-panel.component.html',
	styleUrl: './global-panel.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class GlobalPanelComponent implements AfterViewInit {

	@Input() position: 'start' | 'end' = 'end';
	@Input() autoFocus: 'dialog' | 'first-tabbable' | 'first-heading' | boolean = true;
	@Input() fixedInViewport: boolean = true;
	@Input() fixedTopGap: number = 0;
	@Input() fixedBottomGap: number = 0;
	@Input() disableClose: boolean = true;
	@Input() hasBackdrop: boolean = true;
	@Input() opened: boolean = false;
	@Input() openingMode: 'over' | 'push' | 'side' = 'over';
	@Input() width?: string;
	@Input() mode: EGlobalPanelMode = EGlobalPanelMode.LIGHT;

	@ViewChild('adminSidenav') adminSidenavRef!: MatSidenav;
	@ViewChildren(PanelComponent) panelComponents!: QueryList<PanelComponent>;

	@Output() closedStart = new EventEmitter<void>();
	@Output() openedChange = new EventEmitter<boolean>();
	@Output() openedStart = new EventEmitter<void>();

	constructor(private sidenavService: SidenavService) { }

	ngAfterViewInit() {
		this.listenOnSidenavOpen();
		this.listenOnSidenavClose();
		this.listenOnMatSidenavCloseFinish();
	}

	private listenOnSidenavOpen() {
		this.sidenavService.open$.subscribe(() => this.adminSidenavRef.open());
	}

	private listenOnSidenavClose() {
		this.sidenavService.close$.subscribe(() => this.adminSidenavRef.close());
	}

	private listenOnMatSidenavCloseFinish() {
		this.adminSidenavRef.openedChange
			.pipe(
				filter((status: boolean) => !status),
				tap(() => this.sidenavService.detachComponent())
			)
			.subscribe();
	}

	onKeyDownEscape() {
		this.sidenavService.close();
	}

	onBackDropClick() {
		this.sidenavService.close();
	}
	
	/**
	 * Closes the sidenav panel and emits the close event.
	 * 
	 * @remarks
	 * This method implements a hierarchical closing behavior for nested panels:
	 * 
	 * - If there is a nested panel that is currently open and its width exceeds
	 *   the parent panel's width, this method will close the nested panel first
	 * - Otherwise, it will close the parent panel
	 * 
	 * This behavior ensures a proper visual hierarchy and user experience when
	 * dealing with nested panels of different widths.
	 * 
	 */
	close() {
		const panel = this.sidenavService.getPanelRef();
		if (panel?.adminDrawerRef?.opened) {
			panel.adminDrawerRef.close();
		} else {
			this.adminSidenavRef.close();
		}
	}

}