import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatListModule } from '@angular/material/list';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ETextButtonMode, ETextButtonType, TextButtonComponent } from '../../buttons/text-button/text-button.component';

export interface IAdminSimpleListOption {
  id: string;
  text: string;
	hasImage?: boolean;
  image?: string;
  altImage?: string;
  imgError?: boolean;
  hasButton?: boolean;
	buttonId?: string;
	buttonText?: string;
	buttonIcon?: string;
	/** Begin deprecated input */
	buttonIconFontFamily?: string;
	/** End deprecated input */
}

export enum EAdminSimpleListMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-simple-list',
  standalone: true,
  imports: [
    MatListModule,
    MatButtonModule,
    ImageComponent,
		TextButtonComponent,
		IconComponent
  ],
  templateUrl: './simple-list.component.html',
  styleUrl: './simple-list.component.scss',
  encapsulation: ViewEncapsulation.None
})

export class SimpleListComponent {
  @Input() id: string = '';
  @Input() visibleItems: number = 5;
  @Input() showAll: boolean = false; 
  @Input() options: IAdminSimpleListOption[] = []; 
  @Input() textSeeLess: string = '';
  @Input() textSeeMore: string = '';
  @Input() mode: EAdminSimpleListMode = EAdminSimpleListMode.LIGHT;
	@Input() hasOptionsToggleVisibility: boolean = true;

	@Output() buttonClicked = new EventEmitter<void>();

  imgError = false;
  ImgEntityType = ImgEntityType;
  EImgMode = EImgMode;
  EAdminSimpleListMode = EAdminSimpleListMode;
  ETextButtonMode = ETextButtonMode;
  EIconName = EIconName;
	buttonType = ETextButtonType.BUTTON;

  visibleOptions: any[] = []; // Subconjunto de opciones visibles

  ngOnChanges() {
    // Se ejecuta cada vez que cambian los inputs
    this.updateVisibleOptions();
  }

  toggleView() {
    this.showAll = !this.showAll;
    this.visibleItems = this.showAll ? this.options.length : 5;
    this.updateVisibleOptions();
  }

  updateVisibleOptions() {
    // Si hasOptionsToggleVisibility es false, mostrar todos los elementos
    // Si es true, usar la lógica de showAll y visibleItems
    if (!this.hasOptionsToggleVisibility) {
      this.visibleOptions = this.options;
    } else {
      if (this.showAll) {
        this.visibleOptions = this.options;
      } else {
        this.visibleOptions = this.options.slice(0, this.visibleItems);
      }
    }
  }

  handleImageError(option: IAdminSimpleListOption) {
    option.imgError = true;
  }

}
