import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ETextButtonMode, ETextButtonType, TextButtonComponent } from '../../buttons/text-button/text-button.component';
import { CheckboxComponent, ECheckboxMode } from '../../forms/checkbox/checkbox.component';

export enum EAdminCommentMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-comment',
  standalone: true,
  imports: [
		CheckboxComponent,
    ImageComponent,
		TextButtonComponent,
		IconComponent
	],
  templateUrl: './comment.component.html',
  styleUrl: './comment.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class CommentComponent {
	@Input() mode = EAdminCommentMode.LIGHT;
	@Input() id: string = '';
	@Input() idCheckbox?: string;
	@Input() hasCheckbox?: boolean;
	@Input() image?: string;
	@Input() altImage?: string;
	@Input() imgError?: boolean;
	@Input() title: string = '';
	@Input() subtitle: string = '';
	@Input() nameLink?: boolean;
	@Input() textButtonId: string = '';

	ImgEntityType = ImgEntityType;
	ECheckboxMode = ECheckboxMode;
	EImgMode = EImgMode;
	EAdminCommentMode = EAdminCommentMode;
	textButtonType = ETextButtonType.BUTTON;
	ETextButtonMode = ETextButtonMode;
	EIconName = EIconName;

	handleImageError() {
    this.imgError = true;
  }

	@Output() buttonClicked = new EventEmitter<void>();
	@Output() commentCheckboxClicked = new EventEmitter<void>();
}
