import { Component, Input, ViewEncapsulation, booleanAttribute, output } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum ECanvasCardMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum ECanvasCardType {
  PRIMARY = 'primary',
  SECONDARY = 'secondary',
}

@Component({
  selector: 'admin-canvas-card',
  standalone: true,
  imports: [
    MatCardModule,
    ButtonComponent
  ],
  templateUrl: './canvas-card.component.html',
  styleUrl: './canvas-card.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class CanvasCardComponent {
  @Input() id: string = '';
  @Input() title: string = '';
  @Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;
  @Input() mode: ECanvasCardMode = ECanvasCardMode.LIGHT;
  @Input() type: ECanvasCardType = ECanvasCardType.PRIMARY;
  @Input() buttonText: string = '';
  @Input() buttonTooltip: string = '';

  deleteClicked = output<void>();
  buttonClicked = output<void>();

  buttonButtonTypeDefault = EButtonButtonType.MATICONBUTTON;
  buttonColorDefault = EButtonColor.PRIMARY;
  buttonTypeDefault = EButtonType.SUBMIT;
  EButtonMode = EButtonMode;
	ECanvasCardMode = ECanvasCardMode;
	EIconName = EIconName;
}
