import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EProgressBarColor } from '../../atoms/progress-bar/progress-bar.component';
import { EProgressBarWithButtonMode, ProgressBarWithButtonComponent } from '../../blocks/progress-bar-with-button/progress-bar-with-button.component';

export enum ESidenavMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-sidenav',
	standalone: true,
	imports: [
		MatIconModule,
		ProgressBarWithButtonComponent,
		IconComponent
	],
	templateUrl: './sidenav.component.html',
	styleUrl: './sidenav.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class SidenavComponent {

	@Input() opened: boolean = true;
	@Input() title?: string;
	@Input() icon?: EIconName;
	@Input() progressBarText?: string;
	@Input() progressBarValue: number = 45;
	@Input() progressBarColor = EProgressBarColor.ACCENT;
	@Input() buttonText?: string;
	@Input() mode = ESidenavMode.LIGHT;

	@Output() toggleSidenav = new EventEmitter<void>();
	@Output() sidenavFooterButtonClicked = new EventEmitter<Event>();

	EProgressBarWithButtonMode = EProgressBarWithButtonMode;
	ESidenavMode = ESidenavMode;
	EIconName = EIconName;
	
}