import { NgClass } from '@angular/common';
import { Component, EventEmitter, Input, Output, SimpleChanges, ViewEncapsulation, booleanAttribute } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatIconModule } from '@angular/material/icon';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EButtonButtonType, EButtonColor } from '../../buttons/button/button.component';
import { EAdminMenuMode, IAdminMenuOption, MenuComponent } from '../../buttons/menu/menu.component';
import { EEntityTypes } from '../../types/common.types';

export enum EAdaptativeResourceCardMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-adaptive-resource-card',
  standalone: true,
  imports: [
    MatCardModule,
    MatIconModule,
    MenuComponent,
    NgClass,
    IconComponent,
  ],
  templateUrl: './adaptive-resource-card.component.html',
  styleUrl: './adaptive-resource-card.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class AdaptiveResourceCardComponent {

  cardIcon!:EIconName;

  @Input() id: string = '';
  @Input() type!: EEntityTypes;
  @Input() text: string = '';
  @Input() subtext: string = '';
  @Input() image?: string;
  @Input() options: IAdminMenuOption[] = [];
  @Input() selected?: boolean;
  @Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;
  @Input() mode: EAdaptativeResourceCardMode = EAdaptativeResourceCardMode.LIGHT;

  @Output() buttonClicked = new EventEmitter<Event>();
  @Output() optionClicked = new EventEmitter<IAdminMenuOption>();

  buttontype = EButtonButtonType.MATICONBUTTON;
  color = EButtonColor.PRIMARY;

	EAdaptativeResourceCardMode = EAdaptativeResourceCardMode;
	EAdminMenuMode = EAdminMenuMode;
	EIconName = EIconName;

  handleClick(event: Event) {
    this.buttonClicked.emit(event);
  }

  typeOptions: Array<{
    types: Array<EEntityTypes>;
    icon: EIconName;
  }> = [
    {
      types: [EEntityTypes.ELEARNING],
      icon: EIconName.SCHOOL,
    },
    {
      types: [EEntityTypes.IMAGE],
      icon: EIconName.IMAGE,
    },
    {
      types: [EEntityTypes.AUDIO],
      icon: EIconName.HEADPHONES,
    },
    {
      types: [EEntityTypes.DOC],
      icon: EIconName.DESCRIPTION,
    },
    {
      types: [EEntityTypes.PDF],
      icon: EIconName.CUSTOM_PDF,
    },
    {
      types: [EEntityTypes.ZIP],
      icon: EIconName.FOLDER_ZIP,
    },
    {
      types: [EEntityTypes.VIDEO],
      icon: EIconName.ONDEMAND_VIDEO,
    },
    {
      types: [EEntityTypes.EXCEL],
      icon: EIconName.CUSTOM_EXCEL,
    },
    {
      types: [EEntityTypes.WORD],
      icon: EIconName.CUSTOM_WORD,
    },
    {
      types: [EEntityTypes.POWERPOINT],
      icon: EIconName.CUSTOM_POWERPOINT,
    },
  ];

ngOnChanges(changes: SimpleChanges): void {
  if (changes['type']) {
    this.getTypeDetails();
  }
}

private getTypeDetails() {
    const typeDetail = this.typeOptions.find(option => option.types.includes(this.type));
    if (typeDetail) {
      this.cardIcon = typeDetail.icon;
    }
    return null;
  }
}
