import { NgClass } from '@angular/common';
import { Component, Input, ViewEncapsulation, booleanAttribute } from '@angular/core';

export enum IAdminInfoListMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-info-list',
  standalone: true,
  imports: [
    NgClass
  ],
  templateUrl: './info-list.component.html',
  styleUrl: './info-list.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class InfoListComponent {
  @Input() id: string = ''; 
  @Input() title: string = ''; 
  @Input() hasBorder: boolean = false;
  @Input() mode = IAdminInfoListMode.LIGHT;
  @Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;

  imgError = false;
  
  handleImageError() {
    this.imgError = true;
  }
}
