import { Component, computed, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatTabsModule } from '@angular/material/tabs';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export interface ITabsLink {
  id: string;
  text: string;
  disabled?: boolean;
  active?: boolean;
}

export enum ETabsMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-tabs',
  standalone: true,
  imports: [
    MatTabsModule,
    ButtonComponent,
  ],
  templateUrl: './tabs.component.html',
  styleUrl: './tabs.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class TabsComponent {

  @Input() selectedIndex: number = 0;
  @Input() links: ITabsLink[] = [];
  @Input() mode: ETabsMode = ETabsMode.LIGHT;
  @Input() textButton: string = '';
  @Input() typeButton: EButtonType = EButtonType.BUTTON;
  @Input() tooltipButton: string = '';
  @Input() disabledButton: boolean = false;
  @Input() leftIconButton?: EIconName;
  @Input() hasAction: boolean = false;

  @Output() linkClicked = new EventEmitter<{link: ITabsLink, selectedIndex: number}>();
  @Output() actionButtonClicked = new EventEmitter<void>();

	EButtonColor = EButtonColor;
	buttonMode = computed(() => this.mode === ETabsMode.DARK ? EButtonMode.DARK : EButtonMode.LIGHT);

}
