import { Component, Input, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EProgressSpinnerColor, EProgressSpinnerMode, ProgressSpinnerComponent } from '../progress-spinner/progress-spinner.component';

export enum EDisclaimerMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum EDisclaimerColor {
  PRIMARY = 'primary',
  ACCENT = 'accent',
	ALERT = 'alert',
  WARN = 'warn',
  SUCCESS = 'success',
  EXTRA = 'extra',
}

@Component({
  selector: 'admin-disclaimer',
  standalone: true,
  imports: [
    MatIconModule,
    IconComponent,
    ProgressSpinnerComponent
  ],
  templateUrl: './disclaimer.component.html',
  styleUrl: './disclaimer.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class DisclaimerComponent {

  @Input() id?: string;
  @Input() mode: EDisclaimerMode = EDisclaimerMode.LIGHT;
  @Input() text: string = 'Label';
  @Input() color = EDisclaimerColor.PRIMARY;
  @Input() icon?: EIconName;
  @Input() hasProgressSpinner: boolean = false;
  @Input() modeProgressSpinner = EProgressSpinnerMode.INDETERMINATE;
  @Input() diameter: number = 20;
  @Input() strokeWidth: number = 2;
  
  getProgressSpinnerColor(): EProgressSpinnerColor {
    switch (this.color) {
      case EDisclaimerColor.PRIMARY:
        return EProgressSpinnerColor.PRIMARY;
      case EDisclaimerColor.ACCENT:
        return EProgressSpinnerColor.ACCENT;
      case EDisclaimerColor.WARN:
        return EProgressSpinnerColor.WARN;
      case EDisclaimerColor.SUCCESS:
        return EProgressSpinnerColor.SUCCESS;
      case EDisclaimerColor.EXTRA:
        return EProgressSpinnerColor.EXTRA;
      case EDisclaimerColor.ALERT:
        return EProgressSpinnerColor.ALERT;
      default:
        return EProgressSpinnerColor.PRIMARY;
    }
  }
}
