import { CommonModule } from '@angular/common';
import { Component, ComponentRef, Input, OnDestroy, OnInit, Type, ViewChild, ViewContainerRef } from '@angular/core';
import { Observable, Subject, takeUntil } from 'rxjs';

@Component({
  selector: 'admin-cell-wrapper',
  standalone: true,
  imports: [
    CommonModule
  ],
  templateUrl: './cell-wrapper.component.html',
  styleUrls: ['./cell-wrapper.component.scss']
})
export class CellWrapperComponent implements OnInit, OnDestroy {

  @Input() componentType!: Type<any>;
  @Input() inputs: { [key: string]: any } = {};
  @Input() outputs: { [key: string]: (event: any) => void } = {};
  @ViewChild('componentContainer', { read: ViewContainerRef, static: true })
  componentContainer!: ViewContainerRef;
  
  private componentRef: ComponentRef<any> | null = null;
  private destroy$ = new Subject<void>();

  ngOnInit(): void {
    this.createComponent();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
    this.removeChildComponent();
  }

  private createComponent(): void {
    if (!this.componentType) {
      return;
    }

    this.removeChildComponent();
    this.componentRef = this.componentContainer.createComponent(this.componentType);
    this.updateInputs();
    this.updateOutputs();
  }

  private updateInputs(): void {
    if (!this.componentRef) {
      return;
    }

    for (const [key, value] of Object.entries(this.inputs)) {
      this.componentRef.instance[key] = value;
    }
    
    this.componentRef.changeDetectorRef.detectChanges();
  }

  private updateOutputs(): void {
    if (!this.componentRef) {
      return;
    }

    for (const [outputName, handler] of Object.entries(this.outputs)) {
      if (this.componentRef.instance[outputName]) {
        const output$ = this.componentRef.instance[outputName] as Observable<any>;
        
        output$
          .pipe(takeUntil(this.destroy$))
          .subscribe((event: any) => {
            handler(event);
          });
      }
    }
  }

  private removeChildComponent(): void {
    if (this.componentRef) {
      this.componentRef.destroy();
      this.componentRef = null;
    }
  }
} 