import { FlatTreeControl } from '@angular/cdk/tree';
import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, OnInit, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTreeFlatDataSource, MatTreeFlattener, MatTreeModule } from '@angular/material/tree';
import { EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EButtonButtonType, EButtonColor } from '../../buttons/button/button.component';
import { EAdminMenuMode, IAdminMenuOption, MenuComponent } from '../../buttons/menu/menu.component';

export enum EAdminTreeMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export interface IAdminTreeNode {
  [key: string]: any;
  children?: IAdminTreeNode[];
}

export interface IAdminTreeNodeClickEvent {
  node: IAdminTreeNode;
  isExpanded: boolean;
}

interface IAdminTreeFlatNode {
  expandable: boolean;
  level: number;
  label: string;
  icon?: EIconName;
  raw: IAdminTreeNode;
	options?: IAdminMenuOption[];
}

@Component({
  selector: 'admin-tree',
  standalone: true,
  imports: [
		CommonModule,
		MatTreeModule,
		MatIconModule,
		MatButtonModule,
		IconComponent,
		MenuComponent
	],
  templateUrl: './tree.component.html',
  styleUrl: './tree.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class TreeComponent implements OnInit {

  @Input() mode: EAdminTreeMode = EAdminTreeMode.LIGHT;
  @Input() data: IAdminTreeNode[] = [];
  @Input() labelKey: string = 'label';
  @Input() childrenKey: string = 'children';
	@Input() globalIcon?: EIconName;

	@Output() nodeClick = new EventEmitter<IAdminTreeNodeClickEvent>();
	@Output() optionClicked = new EventEmitter<IAdminMenuOption>();

	EIconName = EIconName;
	EAdminTreeMode = EAdminTreeMode;
	EIconMode = EIconMode;
	EAdminMenuMode = EAdminMenuMode;
	EButtonButtonType = EButtonButtonType;
	EButtonColor = EButtonColor;
	buttontype = EButtonButtonType.MATICONBUTTON;
  color = EButtonColor.PRIMARY;

	selectedNode: IAdminTreeFlatNode | null = null;

  treeControl = new FlatTreeControl<IAdminTreeFlatNode>(
    node => node.level,
    node => node.expandable
  );


	ngOnInit(): void {
    this.dataSource.data = Array.isArray(this.data) ? this.data : [];
  }

  private transformer = (node: IAdminTreeNode, level: number): IAdminTreeFlatNode => {
    const children = (node?.[this.childrenKey] as IAdminTreeNode[] | undefined) ?? [];
    const labelValue = (node?.[this.labelKey] ?? '') as string;
    const iconValue = (node?.['icon'] as EIconName | undefined);
    const optionsValue = (node?.['options'] as IAdminMenuOption[] | undefined);
    return {
      expandable: Array.isArray(children) && children.length > 0,
      level,
      label: labelValue,
      icon: iconValue,
      options: optionsValue,
      raw: node
    };
  };

  private treeFlattener = new MatTreeFlattener<IAdminTreeNode, IAdminTreeFlatNode>(
    (n, l) => this.transformer(n, l),
    n => n.level,
    n => n.expandable,
    n => (n?.[this.childrenKey] as IAdminTreeNode[] | undefined) ?? []
  );

  dataSource = new MatTreeFlatDataSource(this.treeControl, this.treeFlattener);

  hasChild = (_: number, node: IAdminTreeFlatNode) => node.expandable;
  hasNoChild = (_: number, node: IAdminTreeFlatNode) => !node.expandable;

	onNodeClick(node: IAdminTreeFlatNode, event: Event): void {
		event.stopPropagation();
		this.selectedNode = node;
		const isExpanded = this.treeControl.isExpanded(node);
		this.nodeClick.emit({
			node: node.raw,
			isExpanded: isExpanded
		});
	}

	isSelected(node: IAdminTreeFlatNode): boolean {
		return this.selectedNode === node;
	}
}


