import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatListModule } from '@angular/material/list';
import { MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
import { EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonType } from '../../buttons/button/button.component';

export enum EAdminMenuListMode {
	LIGHT = 'light',
	DARK = 'dark'
}

export enum EAdminMenuListType {
	MENU_LIST_ITEM = 'menu-list-item',
	MENU_LIST_NESTED_ITEM = 'menu-list-nested-item'
}

// Propiedades comunes reutilizables (Para la lista principal)
interface IAdminMenuListCommonProps {
	idListItem: string;
  text: string;
	type: EAdminMenuListType;
	disabled?: boolean;
	options?: IAdminMenuListNestedOption[];
	idNestedList?: string;
}

// Caso con icono izquierdo (iconFontFamily obligatorio) (Para la lista principal)
interface IAdminMenuListWithLeftIcon extends IAdminMenuListCommonProps {
	icon: EIconName;
}

// Caso sin icono izquierdo (iconFontFamily no permitida) (Para la lista principal)
interface IAdminMenuListWithoutLeftIcon extends IAdminMenuListCommonProps {
	icon?: undefined;
}

// Caso con icono derecho (rightIconFontFamily obligatorio) (Para la lista principal)
interface IAdminMenuListWithRightIcon extends IAdminMenuListCommonProps {
	rightIcon: EIconName;
}

// Caso sin icono derecho (rightIconFontFamily no permitida) (Para la lista principal)
interface IAdminMenuListWithoutRightIcon extends IAdminMenuListCommonProps {
	rightIcon?: undefined;
}

// Combinaciones de interfaces para iconos izquierdos y derechos (Para la lista principal)
interface IAdminMenuListWithBothIcons extends IAdminMenuListWithLeftIcon, IAdminMenuListWithRightIcon {}
interface IAdminMenuListWithLeftIconOnly extends IAdminMenuListWithLeftIcon, IAdminMenuListWithoutRightIcon {}
interface IAdminMenuListWithRightIconOnly extends IAdminMenuListWithoutLeftIcon, IAdminMenuListWithRightIcon {}
interface IAdminMenuListWithoutIcons extends IAdminMenuListWithoutLeftIcon, IAdminMenuListWithoutRightIcon {}

// Interface para la lista principal
export type IAdminMenuListOption = IAdminMenuListWithBothIcons | IAdminMenuListWithLeftIconOnly | IAdminMenuListWithRightIconOnly | IAdminMenuListWithoutIcons;


// Propiedades comunes reutilizables (Para la lista anidada)
interface IAdminMenuListNestedOptionCommonProps {
	idNestedList: string;
  textNestedList: string;
  disabledNestedList?: boolean;
	hasCheckIconNestedList?: boolean;
}

// Caso con icono (iconFontFamily obligatorio) (Para la lista anidada)
interface IAdminMenuListNestedOptionWithIcon extends IAdminMenuListNestedOptionCommonProps {
  iconNestedList: EIconName;
}

// Caso sin icono (iconFontFamily no permitida) (Para la lista anidada)
interface IAdminMenuListNestedOptionWithoutIcon extends IAdminMenuListNestedOptionCommonProps {
	iconNestedList?: undefined;
}

// Interface para la lista anidada
export type IAdminMenuListNestedOption = IAdminMenuListNestedOptionWithIcon | IAdminMenuListNestedOptionWithoutIcon;


@Component({
  selector: 'admin-menu-list',
  standalone: true,
  imports: [
		MatListModule,
		ButtonComponent,
    MatIconModule,
    IconComponent,
    MatMenuModule,
		CommonModule
	],
  templateUrl: './menu-list.component.html',
  styleUrl: './menu-list.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class MenuListComponent {
	@Input() listItems: IAdminMenuListOption[] = [];
  @Input() id: string = '';
	@Input() disabled: boolean = false;
	@Input() mode = EAdminMenuListMode.LIGHT;

	@Output() optionClicked = new EventEmitter<IAdminMenuListOption>();
	@Output() nestedOptionClicked = new EventEmitter<IAdminMenuListNestedOption>();

	buttonButtonTypeDefault = EButtonButtonType.MATICONBUTTON;
  buttonColorDefault = EButtonColor.PRIMARY;
  buttonTypeDefault = EButtonType.SUBMIT;
	EIconMode = EIconMode;
	EAdminMenuListMode = EAdminMenuListMode;
	EIconName = EIconName;

	handleClick(listItem: IAdminMenuListOption) {
    this.optionClicked.emit(listItem);
  }
	handleNestedItemClick(option: IAdminMenuListNestedOption) {
    this.nestedOptionClicked.emit(option);
  }
	openMenu(menuTrigger: MatMenuTrigger): void {
    if (this.disabled) {
      menuTrigger.closeMenu();
    } else {
      menuTrigger.openMenu();
    }
  }
}
