import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, forwardRef, Input, input, model, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

export enum ESearchboxMode {
  LIGHT = 'light',
  DARK = 'dark'
}

let nextUniqueId = 0;
const selector ='admin-searchbox';

@Component({
  selector,
  standalone: true,
  imports: [
		CommonModule, 
		MatButtonModule, 
		IconComponent
	],
  templateUrl: './searchbox.component.html',
  styleUrl: './searchbox.component.scss',
	encapsulation: ViewEncapsulation.None,
  host: {
    'id': '',
    '[class.disabled]': 'disabled'
  },
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => SearchboxComponent),
      multi: true
    }
  ]
})
export class SearchboxComponent implements ControlValueAccessor{

  id = input<string>(`${selector}-${nextUniqueId++}`);
  label = input<string>('Search')
  value = model<string>('');
  placeholder = input<string>('Search');
  @Input({ transform: booleanAttribute }) disabled = false;
  @Input() mode: ESearchboxMode = ESearchboxMode.LIGHT;

  onChange: ((value: string) => void) = () => {};
  onTouched: (() => void) = () => {};

  ESearchboxMode = ESearchboxMode;
  EIconName = EIconName;

  writeValue(value: string): void {
    this.value.set(value);
  }
  registerOnChange(fn: (_: string) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () =>void): void {
    this.onTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabled = isDisabled;
  }

  updateValue(val: string) {
    if (!this.disabled && val !== this.value()) {
      this.writeValue(val);
      this.onChange(val);
      this.onTouched();
    }
  }

}