import { Component, EventEmitter, Input, Output, booleanAttribute } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum IAdminInfoBlockMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-info-block',
  standalone: true,
  imports: [
		ButtonComponent,
		IconComponent,
	],
  templateUrl: './info-block.component.html',
  styleUrl: './info-block.component.scss'
})
export class InfoBlockComponent {

	@Input() id: string = ''; 
	@Input() mode = IAdminInfoBlockMode.LIGHT;
  @Input() title: string = '';
	@Input() buttonType: EButtonType = EButtonType.BUTTON;
	@Input() buttonButtonType: EButtonButtonType = EButtonButtonType.MATBUTTON;
	@Input() buttonColor: EButtonColor = EButtonColor.PRIMARY;
	@Input() buttonIcon?: EIconName;
	@Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;

	@Output() buttonClicked = new EventEmitter<void>();

	EButtonButtonType = EButtonButtonType;
	EButtonColor = EButtonColor;
	EButtonType = EButtonType;
	EIconName = EIconName;
	EButtonMode = EButtonMode;
	IAdminInfoBlockMode = IAdminInfoBlockMode;

	onButtonClicked(): void {
		this.buttonClicked.emit();
	}
}
