import { Renderer2 } from '@angular/core';
import { attemptFocus } from './attempt-focus.fn';
import { getFocusableItems } from './get-focusable-items.fn';

export function setTrapFocus(element: Element, renderer: Renderer2) {
	let changingFocus = false;
	const parent: HTMLElement = renderer.parentNode(element);
	if (!(parent instanceof HTMLElement)) {
		return;
	}
	const trapFocus1: HTMLElement = renderer.createElement('div');
	const trapFocus2: HTMLElement = renderer.createElement('div');
	renderer.setAttribute(trapFocus1, 'tabindex', '0');
	renderer.setAttribute(trapFocus2, 'tabindex', '0');
	renderer.insertBefore(parent, trapFocus1, element);
	renderer.appendChild(parent, trapFocus2);
	parent.addEventListener('keyup', $event => {
		if (
			changingFocus ||
			!($event instanceof KeyboardEvent) ||
			$event.defaultPrevented ||
			$event.code !== 'Tab'
		) {
			return;
		}
		changingFocus = true;
		$event.preventDefault();
		$event.stopPropagation();
		const focusableChildren = getFocusableItems(element);
		if (!element.contains(($event.target as Node) ?? null)) {
			attemptFocus(
				$event.shiftKey
					? focusableChildren[focusableChildren.length - 1]
					: focusableChildren[0]
			);
		}
		changingFocus = false;
	});
}
