import { Component, Input, output } from '@angular/core';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum EDragAndDropMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-drag-and-drop',
  standalone: true,
  imports: [
		ButtonComponent,
	],
  templateUrl: './drag-and-drop.component.html',
  styleUrl: './drag-and-drop.component.scss'
})
export class DragAndDropComponent {

	@Input() id: string = '';
	@Input() title: string = '';
	@Input() subtitle: string = '';
	@Input() buttonText: string = '';
  @Input() buttonTooltip: string = '';
	@Input() icon?: EIconName;
	@Input() buttonButtonType: EButtonButtonType = EButtonButtonType.MATICONBUTTON;
	@Input() buttonColor: EButtonColor = EButtonColor.PRIMARY;
	@Input() buttonType: EButtonType = EButtonType.SUBMIT;
	@Input() mode: EDragAndDropMode = EDragAndDropMode.LIGHT;

  EButtonMode = EButtonMode;
  EDragAndDropMode = EDragAndDropMode;
  EIconName = EIconName;
  
  isDragOver = false;

	buttonClicked = output<void>();
	fileDropped = output<DragEvent>();
	dragOver = output<DragEvent>();
	dragLeave = output<void>();

	onDrop(event: DragEvent): void {
		event.preventDefault();
		this.isDragOver = false;
		this.fileDropped.emit(event);
	}

	onDragOver(event: DragEvent): void {
		event.preventDefault();
		this.isDragOver = true;
		this.dragOver.emit(event);
	}

	onDragLeave(event: DragEvent): void {
		event.preventDefault();
		this.isDragOver = false;
		this.dragLeave.emit();
	}
}
