import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ImageComponent, ImgEntityType } from '../../atoms/image/image.component';

export enum EButtonType {
  BUTTON = 'button',
  SUBMIT = 'submit',
  RESET = 'reset'
}
export enum EButtonButtonType {
  MATBUTTON = 'mat-button',
  MATFLATBUTTON = 'mat-flat-button',
  MATSTROKEDBUTTON = 'mat-stroked-button',
  MATICONBUTTON = 'mat-icon-button',
}
export enum EButtonColor {
  PRIMARY = 'primary',
  ACCENT = 'accent',
  WARN = 'warn',
  WHITE = 'white',
}
export enum EButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}
export enum EButtonSize {
  SMALL = 'small',
  LARGE = 'large',
}

@Component({
  selector: 'admin-button',
  standalone: true,
  templateUrl: './button.component.html',
  imports: [
    CommonModule,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    IconComponent,
    ImageComponent,
  ],
  styleUrls: ['./button.component.scss'],
  encapsulation: ViewEncapsulation.None
})
export class ButtonComponent {
	
  @Input() mode: EButtonMode = EButtonMode.LIGHT;
  @Input() id: string = '';
  @Input() text: string = '';
  @Input() type = EButtonType.BUTTON;
  @Input() tooltip: string = '';
  @Input() buttonType = EButtonButtonType.MATBUTTON;
  @Input() color = EButtonColor.PRIMARY;
  @Input() size = EButtonSize.LARGE;
  @Input() disabled: boolean = false;
  @Input() leftIcon?: EIconName;
  @Input() rightIcon?: EIconName;
  @Input() form: string = '';
  @Input() loadingState: boolean = false;

  @Output() buttonClicked = new EventEmitter<Event>();

	ImgEntityType = ImgEntityType;

  /**
   * Gets the dynamic ImgEntityType for a specific icon
   * @param icon The icon name
   * @returns The corresponding ImgEntityType
   */
  getDynamicImgEntityTypeForIcon(icon: string): ImgEntityType {
    if (!icon) {
      return ImgEntityType.ICON_ANIMATED_DEFAULT;
    }

    const iconKey = icon.toUpperCase();
    const enumKey = `ICON_ANIMATED_${iconKey}` as keyof typeof ImgEntityType;
    
    return ImgEntityType[enumKey] || ImgEntityType.ICON_ANIMATED_DEFAULT;

  }

  handleClick() {
    if (!this.disabled) {
      this.buttonClicked.emit();
    }
  }
}
