import { ComponentType } from '@angular/cdk/overlay';
import { Injectable } from '@angular/core';
import { MatSnackBar, MatSnackBarConfig, MatSnackBarRef } from '@angular/material/snack-bar';

export enum ESnackbarType {
	NEUTRAL = 'neutral',
	WARN = 'warn',
	SUCCESS = 'success'
}

export enum ESnackbarMode {
	DARK = 'dark',
	LIGHT = 'light'
}

const DEFAULT_CONFIG: MatSnackBarConfig = {
	duration: 3000,
	verticalPosition: 'top',
	horizontalPosition: 'right'
};

@Injectable({
	providedIn: 'root'
})
export class SnackBarService {

	constructor(
		private snackBar: MatSnackBar,
	) { }

	open(messageKey: string, mode: ESnackbarMode = ESnackbarMode.LIGHT, type: ESnackbarType = ESnackbarType.NEUTRAL, action?: string, config?: MatSnackBarConfig): MatSnackBarRef<any> {
		const snackBarRef = this.snackBar.open(messageKey, action, {
			...DEFAULT_CONFIG,
			...config,
			panelClass: [`admin-snackbar-${type}`, `admin-snackbar-${mode}`]
		});

		return snackBarRef;
	}

	openWithComponent<T>(component: ComponentType<T>, config?: MatSnackBarConfig): MatSnackBarRef<T> {
		const snackBarRef = this.snackBar.openFromComponent(component, {
			...DEFAULT_CONFIG,
			...config
		});

		return snackBarRef;
	}

}
