import { Component, Input } from '@angular/core';

export enum ECircularProgressBarMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum ECircularProgressBarColor {
  ACCENT = 'accent',
  WARN = 'warn',
  ALERT = 'alert',
	SUCCESS = 'success'
}

@Component({
  selector: 'admin-circular-progress-bar',
  standalone: true,
  imports: [],
  templateUrl: './circular-progress-bar.component.html',
  styleUrl: './circular-progress-bar.component.scss'
})
export class CircularProgressBarComponent {
	@Input() id: string = '';
	@Input() mode = ECircularProgressBarMode.LIGHT;
	@Input() value?: number;
	@Input() color: ECircularProgressBarColor | string | undefined = ECircularProgressBarColor.SUCCESS;

}
