import { isFocusable } from './is-focusable.fn';

export function getFocusableItems(element: Node): Node[] {
	const focusableItems: Node[] = [];
	if (isFocusable(element)) {
		return [element];
	}
	for (let idx = 0; idx < element.childNodes.length; idx++) {
		if (isFocusable(element.childNodes[idx])) {
			focusableItems.push(element.childNodes[idx]);
		} else {
			getFocusableItems(element.childNodes[idx]).forEach(node =>
				focusableItems.push(node)
			);
		}
	}
	return focusableItems;
}
