import { Component, Input, ViewEncapsulation } from '@angular/core';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';

export enum EProgressSpinnerMode {
  DETERMINATE = 'determinate',
  INDETERMINATE = 'indeterminate'
}

export enum EProgressSpinnerColor {
  PRIMARY = 'primary',
  ACCENT = 'accent',
  WARN = 'warn',
  SUCCESS = 'success',
  EXTRA = 'extra',
  ALERT = 'alert',
  WHITE = 'white'
}

export enum EProgressSpinnerModeColor {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-progress-spinner',
  standalone: true,
  imports: [
    MatProgressSpinnerModule
  ],
  templateUrl: './progress-spinner.component.html',
  styleUrl: './progress-spinner.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class ProgressSpinnerComponent {
  @Input() id: string = '';
  @Input() progressMode = EProgressSpinnerMode.INDETERMINATE;
  @Input() value: number = 0;
  @Input() color = EProgressSpinnerColor.PRIMARY;
  @Input() diameter: number = 24;
  @Input() strokeWidth: number = 2;
  @Input() text?: string = '';
  @Input() mode = EProgressSpinnerModeColor.LIGHT;
}
