import { CommonModule } from '@angular/common';
import { AfterViewInit, booleanAttribute, Component, ElementRef, EventEmitter, Input, OnDestroy, OnInit, Output, signal, ViewChild, ViewEncapsulation } from '@angular/core';
import { FormControl, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { MatAutocompleteModule, MatAutocompleteSelectedEvent } from '@angular/material/autocomplete';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MatChipsModule } from '@angular/material/chips';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatTooltipModule } from '@angular/material/tooltip';
import { debounceTime, distinctUntilChanged, Subject, Subscription } from 'rxjs';
import { EIconColor, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EChipGroupMode, EChipGroupTheme, EChipGroupType, IAdminChipGroup } from '../types/chip-group.types';

export interface IChipGroupInputAutocompleteOption {
  id: string;
  text: string;
}

@Component({
  selector: 'admin-chip-group-input',
  templateUrl: 'chip-group-input.component.html',
  styleUrl: 'chip-group-input.component.scss',
  standalone: true,
  host:{'class': 'admin-chip-group-input'},
  encapsulation: ViewEncapsulation.None,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatChipsModule,
    MatIconModule,
    MatInputModule,
    MatTooltipModule,
    IconComponent,
    MatAutocompleteModule,
		MatCheckboxModule,
		MatProgressSpinnerModule
  ],
})
export class ChipGroupInputComponent implements OnInit, OnDestroy, AfterViewInit {

  addOnBlur = true;
  private inputSubject = new Subject<string>();
  private subscription!: Subscription;

  @ViewChild('chipInput') chipInput!: ElementRef<HTMLInputElement>;
  @ViewChild('matFormField', { read: ElementRef }) matFormFieldRef!: ElementRef;
  private resizeObserver?: ResizeObserver;
  private lastHeight: number | null = null;
  public currentWrapperHeight = signal<number | null>(null);
  public wrapperHeightDiff = signal<number | null>(null);

  @Input() autocompleteOptions: IChipGroupInputAutocompleteOption[] = [];
  @Input() chipGroupInputControl: FormControl = new FormControl('');
  @Input() chips: (IAdminChipGroup)[] = [];
  @Input() delay = 0;
  @Input() errorMessages!: {[key:string]: string | boolean};
  @Input() hint!:string;
  @Input() label!: string;
  @Input() placeholder!:string;
	@Input() mode: EChipGroupMode = EChipGroupMode.LIGHT;
	@Input() multipleAutocomplete: boolean = false;
	@Input() loading: boolean = false;
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;

  @Output() addedChip = new EventEmitter<string>();
  @Output() removedChip = new EventEmitter<IAdminChipGroup>();
  @Output() clickedChip = new EventEmitter<IAdminChipGroup>();

  @Output() inputBlurred = new EventEmitter<string>();
  @Output() inputChanged = new EventEmitter<string>();
  @Output() inputFocused = new EventEmitter<string>();
  @Output() optionSelected = new EventEmitter<MatAutocompleteSelectedEvent>();
  @Output() optionToggled = new EventEmitter<{ option: IChipGroupInputAutocompleteOption; checked: boolean }>();

  EChipGroupTheme = EChipGroupTheme;
  EChipGroupMode = EChipGroupMode;
  EIconName = EIconName;
	EIconColor = EIconColor;

  ngOnInit(): void {

    this.subscription = this.inputSubject
      .pipe(
        debounceTime(this.delay),
        distinctUntilChanged(),
      )
      .subscribe(value => {
        this.inputChanged.emit(value);
      });
  }

	typeOptions = [
		{
			type: EChipGroupType.ELEARNING,
			icon: EIconName.SCHOOL,
		},
		{
			type: EChipGroupType.IMAGE,
			icon: EIconName.IMAGE,
		},
		{
			type: EChipGroupType.AUDIO,
			icon: EIconName.HEADPHONES,
		},
		{
			type: EChipGroupType.DOC,
			icon: EIconName.DESCRIPTION,
		},
		{
			type: EChipGroupType.PDF,
			icon: EIconName.CUSTOM_PDF,
		},
		{
			type: EChipGroupType.ZIP,
			icon: EIconName.FOLDER_ZIP,
		},
		{
			type: EChipGroupType.VIDEO,
			icon: EIconName.ONDEMAND_VIDEO,
		},
	];

  /**
   * Lifecycle hook that is called after Angular has fully initialized the component's view.
   *
   * This implementation sets up a ResizeObserver on the Angular Material input wrapper ('.mat-mdc-text-field-wrapper')
   * but only if the 'multipleAutocomplete' input is true. The observer listens for any changes in the height of the wrapper,
   * which can occur due to user interaction, content changes, or window resizing.
   *
   * When a height change is detected, the method:
   * 1. Updates the current height signal (currentWrapperHeight).
   * 2. Calculates the height difference (wrapperHeightDiff) compared to the previous value.
   * 3. Dynamically repositions the overlay panel ('.cdk-overlay-pane') by adjusting its 'top' style property,
   *    ensuring the overlay remains visually aligned with the input field even as its size changes.
   *
   * This approach ensures that overlays (such as autocomplete dropdowns) are always correctly positioned
   * relative to the input, regardless of dynamic UI changes or browser resizing, without manual intervention.
   *
   * The observer is disconnected in ngOnDestroy to prevent memory leaks.
   */
  ngAfterViewInit(): void {
    if (!this.multipleAutocomplete) {
      return;
    }
    setTimeout(() => {
      const wrapper = this.matFormFieldRef?.nativeElement?.querySelector('.mat-mdc-text-field-wrapper');
      if (wrapper) {
        this.currentWrapperHeight.set(wrapper.offsetHeight);
        this.lastHeight = wrapper.offsetHeight;
        this.wrapperHeightDiff.set(null);
        this.resizeObserver = new ResizeObserver(entries => {
          for (let entry of entries) {
            const height = entry.contentRect.height;
            this.wrapperHeightDiff.set(
              this.lastHeight !== null ? height - this.lastHeight : null
            );
            this.currentWrapperHeight.set(height);
            this.lastHeight = height;
            // Reposition the overlay panel to keep it aligned with the input field
            if (this.wrapperHeightDiff() !== null) {
							console.log('wrapperHeightDiff', this.wrapperHeightDiff());
              const overlayPane = document.querySelector('.cdk-overlay-pane:not(.mat-mdc-autocomplete-panel-above)') as HTMLElement;
              if (overlayPane) {
                const currentTop = parseFloat(getComputedStyle(overlayPane).top || '0');
                overlayPane.style.top = (currentTop + this.wrapperHeightDiff()!) + 'px';
              }
            }
          }
        });
        this.resizeObserver.observe(wrapper);
      }
    });
  }

  ngOnDestroy(): void {
    this.resizeObserver?.disconnect();
    this.subscription?.unsubscribe();
  }

  onAdd(): void {
    if(!this.chipInput){
      return;
    }
    const inputValue = this.chipInput.nativeElement.value;
    this.addedChip.emit(inputValue);
    this.chipInput.nativeElement.value = '';
  }

  onInput(event: Event): void {
    const inputValue = (event.target as HTMLInputElement).value;
    this.inputSubject.next(inputValue);
  }

  onFocus(event: Event): void {
    const inputValue = (event.target as HTMLInputElement).value;
    this.inputFocused.emit(inputValue);
  }

  onBlur(event: Event): void {
    const inputValue = (event.target as HTMLInputElement).value;
    this.inputBlurred.emit(inputValue);
  }

  onOptionToggle(option: IChipGroupInputAutocompleteOption, checked: boolean): void {
    this.optionToggled.emit({ option, checked });
  }

  clearInput() {
    if (this.chipInput) {
      this.chipInput.nativeElement.value = '';
    }
  }

  isChipSelected(id: string): boolean {
    return this.chips.some(chip => chip.id === id);
  }

	ngOnChanges() {
		this.chips.forEach(chip => {
			const typeDetail = this.typeOptions.find(option => option.type === chip.type);
			if (typeDetail) {
				chip.iconName = typeDetail.icon as EIconName;
			}

		});
	}

}
