import { Directive, HostBinding, output } from '@angular/core';
import { IDialogableComponent } from '../interfaces/dialogable-component.interface';

/**
 * @deprecated Use new layout components as GlobalPanel, Panel, PopUp and Snackbar
 * This will be removed in the next major version.
 */
@Directive({ standalone: true })
export abstract class BaseDialog<Return = void> implements IDialogableComponent<Return> {
  public onClose = output<Return>();
  @HostBinding('style.inline-size')
  protected readonly width = '512px';
}
