import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum EFloatingChatType {
  SUGGESTIONS = 'suggestions',
  DEFAULT = 'default',
}

export enum EFloatingChatMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum EFloatingChatSize {
  INLINE = 'inline',
  MINIFIED = 'minified'
}

@Component({
  selector: 'admin-floating-chat',
  standalone: true,
  imports: [
		ButtonComponent,
		ImageComponent,
		IconComponent
	],
  templateUrl: './floating-chat.component.html',
  styleUrl: './floating-chat.component.scss',
  encapsulation: ViewEncapsulation.None,
})
export class FloatingChatComponent {
	
	@Input() id: string = '';
	@Input() mode = EFloatingChatMode.LIGHT;
	@Input() type = EFloatingChatType.DEFAULT;
	@Input() size = EFloatingChatSize.MINIFIED;
	@Input() title: string = '';
	@Input() headerImgUrl = '';
	@Input() headerImgAlt = '';
	@Input() iconRight: EIconName = EIconName.SEND;
	@Input() iconColorRight = EButtonColor.PRIMARY;
	@Input() iconLeft: EIconName = EIconName.SEND;
	@Input() iconColorLeft = EButtonColor.PRIMARY;
	@Input() iconTooltipLeft = '';
	@Input() iconTooltipRight = '';

	@Output() iconButtonClickedLeft = new EventEmitter<string>();
	@Output() iconButtonClickedRight = new EventEmitter<string>();

	EFloatingChatMode = EFloatingChatMode;
	EButtonMode = EButtonMode;
	EButtonType = EButtonType;
	EButtonButtonType = EButtonButtonType;
	EFloatingChatType = EFloatingChatType;
	EIconName = EIconName;

	imgError = false;
	ImgEntityType = ImgEntityType;
	ImgMode = EImgMode;

	handleImageError() {
		this.imgError = !this.imgError;
	}
}
