import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ImageComponent, ImgEntityType } from '../../atoms/image/image.component';

export enum EImageMenuButtonType {
  BUTTON = 'button',
  SUBMIT = 'submit',
  RESET = 'reset'
}

export enum EImageMenuButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-image-menu-button',
  standalone: true,
  imports: [
    CommonModule,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    IconComponent,
    ImageComponent
  ],
  templateUrl: './image-menu-button.component.html',
  styleUrl: './image-menu-button.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class ImageMenuButtonComponent {

  @Input() id: string = '';
  @Input() type = EImageMenuButtonType.BUTTON;
  @Input() mode = EImageMenuButtonMode.LIGHT;
  @Input() text?: string;
  @Input() tooltip: string = 'text';
  @Input() disabled: boolean = false;
  @Input() image = '';
	@Input() imageAlt = '';
  @Input() selected: boolean = false;

  imgError = false;
	ImgEntityType = ImgEntityType;
	EIconName = EIconName;

  @Output() buttonClicked = new EventEmitter<Event>();

  handleImageError() {
		this.imgError = !this.imgError;
	}

  handleClick() {
    if (this.disabled) { return; }
    this.buttonClicked.emit();
  }
}
