import { ComponentRef, Injectable, Injector, Type, forwardRef, inject, runInInjectionContext } from '@angular/core';
import { APP_INJECTOR } from '../../utils/tokens/app-injector.token';
import { CREATE_COMPONENT_FN } from '../../utils/tokens/create-component-fn.token';
import { ROOT_ELEMENT } from '../../utils/tokens/root-element.token';
import { BaseDrawerContent } from './components/base-drawer-content.directive';
import { ConfirmDialogComponent } from './components/confirm-dialog/confirm-dialog.component';
import { DrawerComponent } from './components/drawer/drawer.component';
import { IDialogableComponent } from './interfaces/dialogable-component.interface';
import { IOpenDrawerConfig } from './interfaces/open-drawer-config.interface';
import { DIALOG_RENDERER, DialogRenderer } from './tokens/dialog-renderer.token';
import { DialogProps } from './types/dialog-props.type';
import { attemptFocus } from './utils/attempt-focus.fn';
import { getFocusableItems } from './utils/get-focusable-items.fn';
import { setTrapFocus } from './utils/set-trap-focus.fn';

type ConfirmDialogProps = Pick<
	DialogProps<ConfirmDialogComponent>,
	'cancelButtonText'
	| 'confirmButtonText'
	| 'title'
	| 'innerComponent'
> & {
	message?: string;
};
/**
 * @deprecated Use new layout components as GlobalPanel, Panel, PopUp and Snackbar
 * This will be removed in the next major version.
 */
@Injectable({ providedIn: 'root' })
export class DialogService {
	private readonly _appInjector = inject(APP_INJECTOR);
	private readonly _createComponentFn = inject(CREATE_COMPONENT_FN);
	private _renderer?: DialogRenderer;
	private _root?: Element;

	constructor() {
		this._getRenderer();
	}

	private async _getRenderer() {
		runInInjectionContext(this._appInjector, () => {
			const renderer = inject(DIALOG_RENDERER);
			const root = inject(ROOT_ELEMENT);
			(async () => {
				this._renderer = await renderer;
				this._root = this._root ?? await root;
			})();
		});
	}

	openDrawer<T extends BaseDrawerContent<Return>, Return = unknown>(config: IOpenDrawerConfig<T, Return>) {
		const { component, dialog, showModal } =
			this._createDialog<DrawerComponent<T, Return>>(
				forwardRef(() => DrawerComponent),
				{
					title: config.title,
					width: config.width ?? '100%',
					contentCmp: config.component.type,
					contentProps: config.component.inputs
				},
				config.injector) ?? {};
		if (!component || !dialog || !showModal) {
			return;
		}
		this._renderer?.addClass(dialog, 'drawer');
		showModal();
		return component;
	}

	openCustomDrawer<T extends IDialogableComponent>(
		cmp: Type<T>,
		props: Partial<DialogProps<T>> = {}
	) {
		const { component, dialog, showModal } =
			this._createDialog(cmp, props) ?? {};
		if (!component || !dialog || !showModal) {
			return;
		}
		this._renderer?.addClass(dialog, 'drawer');
		showModal();
		return component;
	}

	openConfirmDialog(props: ConfirmDialogProps) {
		const { component, dialog, showModal } =
			this._createDialog(forwardRef(() => ConfirmDialogComponent), props) ?? {};
		if (!component || !dialog || !showModal) {
			return;
		}
		this._renderer?.addClass(dialog, 'confirm');
		showModal();
		return component;
	}

	openCustomDialog<T extends IDialogableComponent>(
		cmp: Type<T>,
		props: Partial<DialogProps<T>> = {}
	) {
		const { component, dialog, showModal } =
			this._createDialog(cmp, props) ?? {};
		if (!component || !dialog || !showModal) {
			return;
		}
		showModal();
		return component;
	}

	private _createDialog<T extends IDialogableComponent>(
		component: Type<T>,
		props: Partial<DialogProps<T>> = {},
		inject?: Injector
	) {
		if (!this._renderer) {
			return;
		}
		const content: HTMLElement = this._renderer.createElement('div');
		const dialog: HTMLElement = this._renderer.createElement('div');
		this._renderer.setAttribute(content, 'role', 'dialog');
		this._renderer.appendChild(dialog, content);
		this._renderer.addClass(dialog, 'backdrop');
		const ref = this._createComponentFn(
			component,
			content,
			props,
			inject
		) as ComponentRef<T>;
		const observer = new MutationObserver(mutations => {
			mutations[0].target?.addEventListener(
				'animationend',
				() => {
					observer.disconnect();
					this._renderer!.removeAttribute(content, 'closing');
					this._renderer!.setStyle(dialog, 'display', 'none');
					ref.destroy();
					this._renderer!.removeChild(content, dialog, true);
					this._renderer!.removeChild(this._root!, content, true);
				},
				{ once: true }
			);
		});
		dialog.onkeyup = $event => {
			if ($event.defaultPrevented) {
				return;
			}
			if ($event.code === 'Escape') {
				$event.preventDefault();
				$event.stopPropagation();
				ref.instance.onClose.emit(null);
				return;
			}
		};
		dialog.onmouseup = event => {
			if (event.target === dialog) {
				ref.instance.onClose.emit(null);
			}
		};
		ref.instance.onClose.subscribe(() =>
			this._renderer!.setAttribute(content, 'closing', '')
		);
		this._renderer.addDialog(dialog);
		observer.observe(content, {
			attributes: true,
			attributeFilter: ['closing'],
		});
		return {
			component: ref.instance,
			dialog,
			showModal: () => {
				const focusableChildren = getFocusableItems(content);
				const autoFocus =
					focusableChildren.find(
						child =>
							typeof (child as Element).hasAttribute === 'function' &&
							(child as Element).hasAttribute('autofocus')
					) ?? focusableChildren[0];
				setTimeout(() => {
					attemptFocus(autoFocus);
				}, 1);
				setTrapFocus(content, this._renderer!);
				this._renderer!.addClass(dialog, 'modal');
				this._renderer!.setAttribute(content, 'open', '');
			},
		};
	}
}
