import { NgClass } from '@angular/common';
import { Component, EventEmitter, forwardRef, Input, Output, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatRadioChange, MatRadioModule } from '@angular/material/radio';

export interface IRadioGroupOption {
  value: string;
  label: string;
  disabled?: boolean;
}
export enum ERadioGroupLabelPosition {
  BEFORE = 'before',
  AFTER = 'after'
}
export enum ERadioGroupPosition {
  COLUMN = 'column',
  ROW = 'row'
}

export enum ERadioGroupMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-radio-group',
  standalone: true,
  imports: [ MatFormFieldModule, MatRadioModule, NgClass ],
  templateUrl: './radio-group.component.html',
  styleUrl: './radio-group.component.scss',
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => RadioGroupComponent),
      multi: true
    }
  ]
})
export class RadioGroupComponent implements ControlValueAccessor {

  @Input() disabled!: boolean;
  @Input() labelPosition!: ERadioGroupLabelPosition;
  @Input() name!: string;
  @Input() position!: ERadioGroupPosition;
  @Input() mode = ERadioGroupMode.LIGHT;
  @Input() options: IRadioGroupOption[] = [];
  @Input() radioGroupValue!: string;

  @Output() radioGroupChange: EventEmitter<MatRadioChange> = new EventEmitter<MatRadioChange>();

  value: string = '';
  onChange: (value: string) => void = () => {};
  onTouched: () => void = () => {};

  writeValue(value: string): void {
    this.value = value;
  }

  registerOnChange(fn: (value: string) => void): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }

  setDisabledState?(isDisabled: boolean): void {}

  onRadioChange(change: MatRadioChange): void {
    this.value = change.value;
    this.onChange(change.value);
    this.onTouched();
    this.radioGroupChange.emit(change);
  }
}
