import { CommonModule } from '@angular/common';
import { Component, ElementRef, EventEmitter, HostBinding, Input, Output, ViewChild, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltip } from '@angular/material/tooltip';
import { RouterLink } from '@angular/router';
import { EIconName, IconComponent } from '../../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../../atoms/image/image.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../../buttons/button/button.component';
import { EAdminTableMode } from '../table.component';

export type ChildButtonConfig = {
  buttonType: EButtonButtonType;
  disabled?: boolean;
  color: EButtonColor;
  id?: string | undefined;
  leftIcon?: EIconName;
  rightIcon?: EIconName;
  label?: string;
  tooltip?: string;
  type?: EButtonType;
};

export type ChildIconConfig = {
  icon: EIconName;
};

export type ChildImageConfig = {
  src?: string | undefined;
  alt: string | undefined;
  shape: ImageShape | undefined;
  imgError?: boolean;
};

export enum ETableCellMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export type ChildComponent = 'image' | 'icon' | 'button';

export type ImageShape = 'square' | 'rounded';

export enum ELinkTarget {
  SELF = '_self',
  BLANK = '_blank'
}

export type TableCellConfig = {
  id?: string;
  label?: string;
  link?: {
    url: string
    target?: ELinkTarget
  },
  routerLink?: string | any[];
  childComponent?: ChildComponent;
  childButtonConfig?: ChildButtonConfig;
  childIconConfig?: ChildIconConfig;
  childImageConfig?: ChildImageConfig;
}

@Component({
  selector: 'admin-table-cell',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    ButtonComponent,
    MatIconModule,
    MatTooltip,
		ImageComponent,
		IconComponent
  ],
  templateUrl: './table-cell.component.html',
  styleUrl: './table-cell.component.scss',
  encapsulation: ViewEncapsulation.None,
})
export class TableCellComponent {

  tooltipDisabled!: boolean;

  buttonButtonTypeDefault = EButtonButtonType.MATBUTTON;
  buttonTypeDefault = EButtonType.BUTTON;
  buttonColorDefault = EButtonColor.PRIMARY;
  EAdminTableMode = EAdminTableMode;
  EButtonMode = EButtonMode;
  ETableCellMode = ETableCellMode;

	imgError = false;
	ImgEntityType = ImgEntityType;
	ImgMode = EImgMode;
	EIconName = EIconName;

  @ViewChild('labelElement') labelElement!: ElementRef<HTMLSpanElement>;
  @ViewChild(MatTooltip) tooltip!: MatTooltip;


  @HostBinding('class')
  get dynamicClass() {
    return `admin-table-cell admin-table-cell--text-and-${this.tableCellConfig.childComponent} ${this.mode}`;
  }

  @Input() tableCellConfig!: TableCellConfig;
  @Input() mode: ETableCellMode = ETableCellMode.LIGHT;

  @Output() buttonTableCellClicked = new EventEmitter<string>();

  get linkTarget(): ELinkTarget {
    return this.tableCellConfig?.link?.target ?? ELinkTarget.SELF;
  }

  ngAfterViewInit() {
    // check overflow
    setTimeout(() => {
      this.tooltipDisabled = this.checkOverflow();
    });
  }

  checkOverflow() {
    const element = this.labelElement.nativeElement;
    return element.scrollWidth < element.clientWidth || element.scrollWidth == element.clientWidth
  }

  handleButtonClicked() {
    this.buttonTableCellClicked.emit(this.tableCellConfig.id);
  }

  handleImageError() {
    if (this.tableCellConfig.childImageConfig) {
      this.tableCellConfig.childImageConfig.imgError = true;
    }
  }

  get imageShapeClass(): string {
    const shape = this.tableCellConfig.childImageConfig?.shape || 'square';
    return 'image-shape-' + shape;
  }

}
