import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatChipsModule } from '@angular/material/chips';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { EIconColor, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EChipGroupMode, EChipGroupTheme, EChipGroupType, IAdminChipGroup } from '../types/chip-group.types';

@Component({
	selector: 'admin-chip-group',
	standalone: true,
	imports: [
		CommonModule,
		MatChipsModule,
		MatIconModule,
		MatTooltipModule,
		IconComponent
	],
	templateUrl: './chip-group.component.html',
	styleUrl: './chip-group.component.scss',
	host: { 'class': 'chip-group' },
	encapsulation: ViewEncapsulation.None,
})
export class ChipGroupComponent {
	@Input() mode: EChipGroupMode = EChipGroupMode.LIGHT;
	@Input() chips: IAdminChipGroup[] = [];
	@Input({ transform: coerceBooleanProperty }) selectable: boolean = false;

	@Output() removedChip = new EventEmitter<IAdminChipGroup>();
	@Output() clickedChip = new EventEmitter<IAdminChipGroup>();

	selectedChipIndex!: number;
  EIconColor = EIconColor;
	EChipGroupMode = EChipGroupMode;
  EChipGroupTheme = EChipGroupTheme;
	EIconName = EIconName;

	onRemoved(chip: IAdminChipGroup): void {
		const index = this.chips.indexOf(chip);
		if (index >= 0) {
			this.chips.splice(index, 1);
		}
		this.removedChip.emit(chip);
	}

	onClicked(chip: IAdminChipGroup) {
		const index = this.chips.indexOf(chip);
		this.selectedChipIndex = index;
		this.clickedChip.emit(chip);
	}

	typeOptions = [
		{
			type: EChipGroupType.ELEARNING,
			icon: EIconName.SCHOOL,
		},
		{
			type: EChipGroupType.IMAGE,
			icon: EIconName.IMAGE,
		},
		{
			type: EChipGroupType.AUDIO,
			icon: EIconName.HEADPHONES,
		},
		{
			type: EChipGroupType.DOC,
			icon: EIconName.DESCRIPTION,
		},
		{
			type: EChipGroupType.PDF,
			icon: EIconName.CUSTOM_PDF,
		},
		{
			type: EChipGroupType.ZIP,
			icon: EIconName.FOLDER_ZIP,
		},
		{
			type: EChipGroupType.VIDEO,
			icon: EIconName.ONDEMAND_VIDEO,
		},
	];

	ngOnChanges() {
		this.chips.forEach(chip => {
			const typeDetail = this.typeOptions.find(option => option.type === chip.type);
			if (typeDetail) {
				chip.iconName = typeDetail.icon as EIconName;
			}

		});
	}
}
