import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatSlideToggleChange, MatSlideToggleModule } from '@angular/material/slide-toggle';

export enum ESlideToggleMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-slide-toggle',
  standalone: true,
  imports: [
    MatSlideToggleModule
  ],
  templateUrl: './slide-toggle.component.html',
  styleUrl: './slide-toggle.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class SlideToggleComponent {
  @Input() id!: string;
  @Input() name?: string;
  @Input() arialabel: string = "";
  @Input() disabled: boolean = false;
  @Input() checked?: boolean = false;
  @Input() label: string = 'Slide toggle';
  @Input() isRequired?: boolean;
  @Input() mode: ESlideToggleMode = ESlideToggleMode.LIGHT;

  @Output() slideToggleClicked = new EventEmitter<Event>();
  @Output() change = new EventEmitter<MatSlideToggleChange>;
  
}
