import { Component, EventEmitter, Inject, Input, Output } from '@angular/core';
import { MAT_SNACK_BAR_DATA } from '@angular/material/snack-bar';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export interface SnackbarData {
  id?: string;
  buttonButtonType?: EButtonButtonType;
  buttonColor?: EButtonColor;
  buttonType?: EButtonType;
  text: string;
  buttontext?: string;
  leftIcon?: EIconName;
  rightIcon?: EIconName;
  hasActions?: boolean;
}

export enum ESnackbarMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-snackbar-content',
  standalone: true,
  imports: [
    ButtonComponent,
  ],
  templateUrl: './snackbar-content.component.html',
  styleUrl: './snackbar-content.component.scss'
})
export class SnackbarContentComponent {

  constructor(@Inject(MAT_SNACK_BAR_DATA) public data: SnackbarData) {
    this.id = data.id || '';
    this.text = data.text;
    this.buttonType = data.buttonType || EButtonType.BUTTON;
    this.buttontext = data.buttontext || '';
    this.buttonColor = data.buttonColor || EButtonColor.ACCENT;
    this.buttonButtonType = data.buttonButtonType || EButtonButtonType.MATBUTTON;
    this.leftIcon = data.leftIcon;
    this.rightIcon = data.rightIcon;
    this.hasActions = data.hasActions || false;
  }

  @Input() id: string = '';
  @Input() text: string = '';
  @Input() buttonType = EButtonType.BUTTON;
  @Input() buttonButtonType = EButtonButtonType.MATBUTTON;
  @Input() buttonColor = EButtonColor.ACCENT;
  @Input() buttontext: string = '';
  @Input() leftIcon?: EIconName;
  @Input() rightIcon?: EIconName; 
  @Input() hasActions: boolean = false;
  @Input() mode: ESnackbarMode = ESnackbarMode.LIGHT;

  @Output() snackbarContentButtonClicked = new EventEmitter<void>();

  EButtonButtonType = EButtonButtonType;
  EButtonType = EButtonType;
  EButtonColor = EButtonColor;
  EButtonMode = EButtonMode;
  ESnackbarMode = ESnackbarMode;

}
