import { SelectionModel } from '@angular/cdk/collections';
import { CdkTableModule } from '@angular/cdk/table';
import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  booleanAttribute,
  Component,
  computed,
  ElementRef,
  EventEmitter,
  Input,
  input,
  OnChanges,
  OnInit,
  Output,
  QueryList,
  SimpleChanges,
  ViewChild,
  ViewChildren,
  ViewEncapsulation
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule } from '@angular/material/menu';
import { MatRadioModule } from '@angular/material/radio';
import { MatSort, MatSortModule, Sort } from '@angular/material/sort';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatTooltipModule } from '@angular/material/tooltip';
import { Subject } from 'rxjs';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';
import { IColumnDefinition, IVisibleColumnDefinition } from './table.models';
import { StatusType, TTableRowData } from './types/table.types';

export enum EAdminTableMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-table',
	styleUrl: 'table.component.scss',
	templateUrl: 'table.component.html',
	standalone: true,
	imports: [
		ButtonComponent,
		CommonModule,
		FormsModule,
		MatButtonModule,
		MatCheckboxModule,
		MatIconModule,
		MatMenuModule,
		MatSortModule,
		MatTableModule,
		MatTooltipModule,
		CdkTableModule,
		MatRadioModule,
	],
	encapsulation: ViewEncapsulation.None,
})
export class TableComponent<T extends Record<string, any> = any> implements AfterViewInit, OnChanges, OnInit {

	private destroy$ = new Subject<void>();

	countSelectedRows = 0;

	dataSource!: MatTableDataSource<TTableRowData<T>>;

	noContentPlaceholderImageDefault = 'no-content-illustration.png';

	selectable = input<boolean>(false);
	singleSelection = input<boolean>(false);

	selection?: SelectionModel<TTableRowData<T>>;

	private _isSticked: boolean = false;

	get isSticked(): boolean {
		return this._isSticked;
	}

	set isSticked(value: boolean) {
		this._isSticked = value;
	}

	columnDefinition = input.required<IColumnDefinition[]>();

	columns = computed(() => {
		try {
			const columnDefinition: IColumnDefinition[] = [];
			if (this.selectable()) {
				columnDefinition.push({
					displayName: '#',
					name: 'select',
					visible: true,
				})
			}

			const baseColumns = this.columnDefinition();
			return columnDefinition.concat(baseColumns.filter(column => column.visible));
		} catch (error) {
			// During initialization, columnDefinition might not be available yet
			// Return empty array to prevent NG0950 error
			return [];
		}
	});

  columnNames = computed(() => this.columns().map(column => column.name));

	status = input<StatusType>('loading-data');

	dropdownButtonType = EButtonType.BUTTON;
	dropdownButtonButtonType = EButtonButtonType.MATICONBUTTON;
	dropdownButtonColor = EButtonColor.PRIMARY;
	EAdminTableMode = EAdminTableMode;
	EButtonMode = EButtonMode;
	EIconName = EIconName;

	@Input() rowData: TTableRowData<T>[] = [];
	@Input() selectedData: TTableRowData<T>[] = [];
	@Input() selectionHeaderMessage: string = '';
	@Input() visibleColumnDefinition: IVisibleColumnDefinition[] = [];
	@Input() dropdownButtonTooltip: string = '';
	@Input() mode: EAdminTableMode = EAdminTableMode.LIGHT;
	@Input() stickyHeader = false;
	@Input() parentContainer: HTMLElement | null = null;
	@Input() tableWidth = '100%';
  @Input({ transform: booleanAttribute }) enableSortClear = false;
  @Input() defaultSort: { active: string; direction: 'asc' | 'desc' } | undefined = undefined;
	@Output() getSelectedRows = new EventEmitter<TTableRowData<T>[]>();
	@Output() getSelectedRow = new EventEmitter<TTableRowData<T>>();
	@Output() changeVisibleColumns = new EventEmitter<IVisibleColumnDefinition>();
	@Output() sortChange = new EventEmitter<Sort>();

	@ViewChild(MatSort) sort!: MatSort;
	@ViewChildren('label') labels!: QueryList<ElementRef>;
	@ViewChildren('headerLabel') headerLabels!: QueryList<ElementRef>;

	tooltipDisabledMap = new Map<string, boolean>();
	headerTooltipDisabledMap = new Map<string, boolean>();

	private syncSelection() {
		if (!this.selectable()) {
			this.selection = undefined;
			this.countSelectedRows = 0;
			return;
		}

		const isMultiple = !this.singleSelection();

		if (this.selection) {
			this.selection.clear();
			if (this.selectedData.length > 0) {
				this.selectedData.forEach(item => this.selection!.select(item));
			}
		} else {
			this.selection = new SelectionModel<TTableRowData<T>>(isMultiple, this.selectedData);
		}

		this.countSelectedRows = this.selection.selected.length;
	}

	ngOnChanges(changes: SimpleChanges) {
		this.dataSource = new MatTableDataSource(this.rowData);

		if (changes['selectedData'] || changes['singleSelection']) {
			this.syncSelection();
		}

    if (changes['defaultSort']) {
      this.applyDefaultSort()
    }

		setTimeout(() => {
			this.updateTooltipStates();
		});
	}

	ngOnInit() {
		this.dataSource = new MatTableDataSource(this.rowData);
		this.dataSource.sort = this.sort;
		this.syncSelection();
	}

	ngAfterViewInit() {
    this.sort.sortChange.subscribe((sort: Sort) => {
      this.sortChange.emit(sort);
    });

		this.applyDefaultSort();

		setTimeout(() => {
			this.updateTooltipStates();
		});

		// IntersectionObserver configuration for sticky header
		setTimeout(() => {
			const options = {
				root: this.parentContainer,
				threshold: [0, 1]
			};

			const observer = new IntersectionObserver((entries) => {
				entries.forEach(entry => {
					if (entry.isIntersecting) {
						this.isSticked = false;
					} else {
						this.isSticked = true;
					}
				});
			}, options);

			const guardElement = document.querySelector('.sticky-header-guard');
			if (guardElement) {
				observer.observe(guardElement);
			}
		}, 100);
	}

	private applyDefaultSort(): void {
		if (!this.defaultSort?.active) return;

		this.sort.sort({
			id: this.defaultSort.active,
			start: (this.defaultSort.direction || 'asc') as 'asc' | 'desc',
			disableClear: this.enableSortClear
		});
	}

	updateTooltipStates() {
		this.labels.forEach((labelRef: ElementRef) => {
			const element = labelRef.nativeElement;
			const key = element.getAttribute('data-key') || '';
			const isOverflowing = this.isTextOverflowing(element);
			this.tooltipDisabledMap.set(key, !isOverflowing);
		});

		this.headerLabels.forEach((labelRef: ElementRef) => {
			const element = labelRef.nativeElement;
			const key = element.getAttribute('data-header-key') || '';
			const isOverflowing = this.isTextOverflowing(element);
			this.headerTooltipDisabledMap.set(key, !isOverflowing);
		});
	}

	isTextOverflowing(label: HTMLElement): boolean {
		return label.scrollWidth > label.clientWidth;
	}

	checkTooltipDisabled(key: string): boolean {
		return this.tooltipDisabledMap.get(key) ?? true;
	}

	checkHeaderTooltipDisabled(key: string): boolean {
		return this.headerTooltipDisabledMap.get(key) ?? true;
	}

	isAllSelected(): boolean {
		if (!this.selection) return false;
		const numSelected = this.selection.selected.length;
		const numRows = this.dataSource.data.length;
		return numSelected === numRows;
	}

	masterToggle() {
		console.log('masterToggle');
		if (!this.selection) return;

		if (this.isAllSelected()) {
			// Deselect only enabled rows; keep disabled rows as they are
			this.dataSource.data
				.filter(row => !row.disabled)
				.forEach(row => this.selection?.deselect(row));
		} else {
			// Only select enabled rows
			this.dataSource.data
				.filter(row => !row.disabled)
				.forEach(row => this.selection?.select(row));
		}
		this.countSelectedRows = this.selection.selected.length;
		this.getSelectedRows.emit(this.selection.selected as TTableRowData<T>[]);
	}

	toggleRow(row: TTableRowData<T>, checked: boolean) {
		if (!this.selection) return;

		if (this.singleSelection()) {
			this.selection.clear();
			if (checked) {
				this.selection.select(row);
				this.getSelectedRow.emit(row);
			}
		} else {
			if (checked) {
				this.selection.select(row);
			} else {
				this.selection.deselect(row);
			}
			this.getSelectedRows.emit(this.selection.selected as TTableRowData<T>[]);
		}

		this.countSelectedRows = this.selection.selected.length;
	}

	rowSelect(row: TTableRowData<T>) {
		this.toggleRow(row, true);
	}

	onMenuItemChange(column: IVisibleColumnDefinition, visible: boolean) {
		column.visible = visible;
		this.changeVisibleColumns.emit(column);
	}

}
