import { booleanAttribute, Component, EventEmitter, forwardRef, Injector, Input, OnInit, Output, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, FormControl, FormGroup, FormsModule, NG_VALUE_ACCESSOR, NgControl, ReactiveFormsModule } from '@angular/forms';
import { provideNativeDateAdapter } from '@angular/material/core';
import { DateRange, MatDatepickerModule } from '@angular/material/datepicker';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';

export enum EDatepickerMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-datepicker',
  standalone: true,
  providers: [
    provideNativeDateAdapter(),
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => DatepickerComponent),
      multi: true
    }
  ],
  imports: [
    MatFormFieldModule, MatInputModule, MatDatepickerModule, FormsModule, ReactiveFormsModule
  ],
  templateUrl: './datepicker.component.html',
  styleUrl: './datepicker.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class DatepickerComponent implements ControlValueAccessor, OnInit {

  constructor(public injector: Injector) { }

	@Input() mode: EDatepickerMode = EDatepickerMode.LIGHT;
  @Input({ required: true }) id!:string;
  @Input({ required: true }) label!:string;
  @Input() placeholder!:string;
  @Input() placeholderStartDate:string = '';
  @Input() placeholderEndDate:string = '';
  @Input() hint!:string;
  @Input({ transform: booleanAttribute }) disabled = false;
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;
  @Input() errorMsg!:string;
  @Input() type: 'simple' | 'range' = 'simple';

  @Input() dateValue!: Date;
  @Input() dateRangeValue!: DateRange<Date>;

  @Output() dateChange = new EventEmitter<Date>();
  @Output() dateInput = new EventEmitter<Date>();
  @Output() dateRangeChange = new EventEmitter<DateRange<Date>>();
  @Output() dateRangeInput = new EventEmitter<DateRange<Date>>();

  // ControlValueAccessor implementation
  control = new FormControl();
  onChange: any = () => { };
  onTouched: any = () => { };

  // Internal value management
  private _value: Date | DateRange<Date> | null = null;
  
  // Internal form group for range inputs
  range = new FormGroup({
    start: new FormControl<Date | null>(null),
    end: new FormControl<Date | null>(null)
  });

  get value(): Date | DateRange<Date> | null {
    return this._value;
  }

  set value(val: Date | DateRange<Date> | null) {
    this._value = val;
  }

  // Métodos auxiliares para la plantilla
  getRangeStart(): Date | null {
    return this.type === 'range' && this._value instanceof DateRange ? this._value.start : null;
  }

  getRangeEnd(): Date | null {
    return this.type === 'range' && this._value instanceof DateRange ? this._value.end : null;
  }

  ngOnInit(): void {}

  ngAfterViewInit(): void {
    const ngControl: NgControl = this.injector.get(NgControl, null) as NgControl;
    if (ngControl) {
      setTimeout(() => {
        this.control = ngControl.control as FormControl;
      })
    }
	
  }
  writeValue(value: any): void {
    this._value = value;
    if (this.type === 'range' && value instanceof DateRange) {
      this.range.patchValue({
        start: value.start,
        end: value.end
      });
    }
  }
  registerOnChange(fn: () => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.disabled = isDisabled;
  }
  onDateChange(value: Date): void {
    this._value = value;
    this.dateChange.emit(value);
    this.onChange(value);
    this.onTouched();
  }
  onDateInput(value: Date): void {		
    this._value = value;
    this.dateInput.emit(value);
    this.onChange(value);
    this.onTouched();
  }
  onStartDateChange(value: Date | null): void {
    const currentRange = this._value instanceof DateRange ? this._value : new DateRange<Date | null>(null, null);
    const newRange = new DateRange(value, currentRange.end);
    this._value = newRange;
    this.dateRangeChange.emit(newRange);
    this.onChange(newRange);
    this.onTouched();
  }
  onStartDateInput(value: Date | null): void {
    const currentRange = this._value instanceof DateRange ? this._value : new DateRange<Date | null>(null, null);
    const newRange = new DateRange(value, currentRange.end);
    this._value = newRange;
    this.dateRangeInput.emit(newRange);
    this.onChange(newRange);
    this.onTouched();
  }
  onEndDateChange(value: Date | null): void {
    const currentRange = this._value instanceof DateRange ? this._value : new DateRange<Date | null>(null, null);
    const newRange = new DateRange(currentRange.start, value);
    this._value = newRange;
    this.dateRangeChange.emit(newRange);
    this.onChange(newRange);
    this.onTouched();
  }
  onEndDateInput(value: Date | null): void {
    const currentRange = this._value instanceof DateRange ? this._value : new DateRange<Date | null>(null, null);
    const newRange = new DateRange(currentRange.start, value);
    this._value = newRange;
    this.dateRangeInput.emit(newRange);
    this.onChange(newRange);
    this.onTouched();
  }
}
