import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatProgressBarModule, ProgressAnimationEnd } from '@angular/material/progress-bar';

export enum EProgressMode {
  DETERMINATE = 'determinate',
  INDETERMINATE = 'indeterminate'
}

export enum EProgressBarMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum EProgressBarColor {
  ACCENT = 'accent',
  WARN = 'warn',
  ALERT = 'alert',
	SUCCESS = 'success'
}

export interface IProgressBarSegment {
  value: number;
  color: EProgressBarColor;
}

@Component({
  selector: 'admin-progress-bar',
  standalone: true,
  imports: [
    MatProgressBarModule,
    CommonModule
  ],
  templateUrl: './progress-bar.component.html',
  styleUrl: './progress-bar.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class ProgressBarComponent {

  @Input() id: string = '';
  @Input() progressMode = EProgressMode.DETERMINATE;
	@Input() mode = EProgressBarMode.LIGHT;
  @Input() value: number = 0;
  @Input() color = EProgressBarColor.ACCENT;
  @Input() segments: IProgressBarSegment[] = [];

  @Output() animationEnd = new EventEmitter<ProgressAnimationEnd>();

  get hasSegments(): boolean {
    return this.segments && this.segments.length > 0;
  }

  calculateSegmentValue(segmentIndex: number): number {
    if (!this.hasSegments) return 0;
    
    // Calcular el valor acumulado hasta este segmento
    let accumulatedValue = 0;
    for (let i = 0; i <= segmentIndex; i++) {
      accumulatedValue += this.segments[i].value;
    }
    return accumulatedValue;
  }

  onAnimationEnd(param: ProgressAnimationEnd) {
    this.animationEnd.emit(param);
  }
}
