import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output } from '@angular/core';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode } from '../../buttons/button/button.component';

// Propiedades comunes reutilizables
export interface IFloatingActionButtonOption {
	optionId: string;
	optionIcon: EIconName;
	optionColor: EButtonColor;
	optionTooltip: string;
	action?: () => void;
}

export enum EFloatingActionButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-floating-action-button',
  standalone: true,
  imports: [
		ButtonComponent,
		CommonModule,
	],
  templateUrl: './floating-action-button.component.html',
  styleUrl: './floating-action-button.component.scss'
})
export class FloatingActionButtonComponent {

	@Input() id: string = '';
	@Input() mode = EFloatingActionButtonMode.LIGHT;
	@Input() buttonColor = EButtonColor.ACCENT;
	@Input() buttonTooltipEdit?: string;
	@Input() buttonTooltipClose?: string;
	@Input() options: IFloatingActionButtonOption[] = [];

	@Output() buttonClicked = new EventEmitter<string>();
	@Output() optionClicked = new EventEmitter<IFloatingActionButtonOption>();

	EFloatingActionButtonMode = EFloatingActionButtonMode;
	EButtonMode = EButtonMode;
	EButtonButtonType = EButtonButtonType;

	// Propiedad para controlar la visibilidad de las opciones
	showOptions = false;

	// Getter para el icono dinámico del botón principal
	get buttonIcon(): EIconName {
		return this.showOptions ? EIconName.CLOSE : EIconName.EDIT;
	}

	// Getter para el tooltip dinámico del botón principal
	get buttonTooltip(): string {
		const tooltip = this.showOptions ? this.buttonTooltipClose : this.buttonTooltipEdit;
		return tooltip || '';
	}

	handleButtonClick() {
		// Toggle de las opciones
		this.showOptions = !this.showOptions;
		// Emitir el evento del botón principal
		this.buttonClicked.emit();
	}

	handleClick(option: IFloatingActionButtonOption) {
		if (option.action) {
			option.action();
		}
    this.optionClicked.emit(option);
  }
}
