import {
  InjectionToken,
  Renderer2,
  RendererFactory2,
  inject
} from '@angular/core';
import { ROOT_ELEMENT } from '../../../utils/tokens/root-element.token';
import { DIALOG_RENDERER_CONFIG_TOKEN } from './dialog-renderer-config.token';

export type DialogRenderer = Renderer2 & {
	addDialog: (dialog: HTMLElement) => void;
};

/**
 * @deprecated Use new layout components as GlobalPanel, Panel, PopUp and Snackbar
 * This will be removed in the next major version.
 */
export const DIALOG_RENDERER = new InjectionToken<Promise<DialogRenderer>>(
	'Dialog renderer',
	{
		providedIn: 'root',
		factory: () => {
			const config = inject(DIALOG_RENDERER_CONFIG_TOKEN);
			const rootPromise = inject(ROOT_ELEMENT);
			const rendererFactory = inject(RendererFactory2);
			const fn = async () => {
				let root = await rootPromise;
				const renderer = rendererFactory.createRenderer(
					root,
					config
				) as DialogRenderer;
				renderer['addDialog'] = dialog => renderer.appendChild(root, dialog);
				return renderer;
			};
			return fn();
		},
	}
);
