import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { RouterLink, RouterLinkActive } from '@angular/router';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

export enum ESidenavButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum ESidenavButtonSize {
  SMALL = 'small',
  DEFAULT = 'default'
}

@Component({
  selector: 'admin-sidenav-button',
  standalone: true,
  imports: [
    CommonModule,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    RouterLink,
    RouterLinkActive,
    IconComponent
  ],
  templateUrl: './sidenav-button.component.html',
  styleUrl: './sidenav-button.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class SidenavButtonComponent {
	
  @Input() mode: ESidenavButtonMode = ESidenavButtonMode.LIGHT;
  @Input() id: string = '';
  @Input() text?: string;
  @Input() size: ESidenavButtonSize = ESidenavButtonSize.DEFAULT;
  @Input() tooltip?: string;
  @Input() disabled: boolean = false;
  @Input() icon?: EIconName;
  @Input() routerLink?: string | any[];

  @Output() buttonClicked = new EventEmitter<Event>();

  handleClick() {
    if (this.disabled) { return; }
    this.buttonClicked.emit();
  }
}
