import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { EIconColor, EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EProgressBarColor, EProgressBarMode, ProgressBarComponent } from '../../atoms/progress-bar/progress-bar.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum EProgressBarWithButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-progress-bar-with-button',
	standalone: true,
	imports: [
		IconComponent,
		ButtonComponent,
		ProgressBarComponent
	],
	templateUrl: './progress-bar-with-button.component.html',
	styleUrl: './progress-bar-with-button.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class ProgressBarWithButtonComponent {

	@Input() icon?: EIconName;
	@Input() title: string = '';
	@Input() progressBarText: string = '';
	@Input() progressBarValue: number = 45;
	@Input() progressBarColor = EProgressBarColor.ACCENT;
	@Input() buttonText: string = '';
	@Input() mode = EProgressBarWithButtonMode.LIGHT;

	@Output() sidenavFooterButtonClicked = new EventEmitter<Event>();

	buttonButtonTypeDefault = EButtonButtonType.MATFLATBUTTON;
	buttonColorDefault = EButtonColor.PRIMARY;
	buttonTypeDefault = EButtonType.RESET;
	EButtonMode = EButtonMode;

	EIconColor = EIconColor;
	EIconMode = EIconMode;

	EProgressBarColor = EProgressBarColor;
	EProgressBarWithButtonMode = EProgressBarWithButtonMode;
	EProgressBarMode = EProgressBarMode;

	handleClick() {
		this.sidenavFooterButtonClicked.emit();
	}

}
