import { Component, Input, ViewEncapsulation } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';

export enum EExpertPreviewHeaderMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-expert-preview-header',
  standalone: true,
  imports: [
    ImageComponent,
    IconComponent
  ],
  templateUrl: './expert-preview-header.component.html',
  styleUrl: './expert-preview-header.component.scss',
  encapsulation: ViewEncapsulation.None,
})
export class ExpertPreviewHeaderComponent {
  @Input() id: string = '';
  @Input() mode = EExpertPreviewHeaderMode.LIGHT;
  @Input() title: string = '';
  @Input() subtitle: string = '';
  @Input() image?: string;
  @Input() alt?: string;

  imgError = false;
  ImgEntityType = ImgEntityType;
  EImgMode = EImgMode;
  EExpertPreviewHeaderMode = EExpertPreviewHeaderMode;
  EIconName = EIconName;

  handleImageError() {
    this.imgError = !this.imgError;
  }
}
