import { NgComponentOutlet } from '@angular/common';
import { Component, computed, ElementRef, forwardRef, inject, Injector, input, Type, viewChild } from '@angular/core';
import { CREATE_COMPONENT_FN } from '../../../../utils/tokens/create-component-fn.token';
import { EToolbarPanelHeaderType, ToolbarComponent } from '../../../toolbar/toolbar.component';
import { DialogProps } from '../../types/dialog-props.type';
import { BaseDrawerContent } from '../base-drawer-content.directive';
import { BaseDrawer } from '../base-drawer.directive';

/**
 * @deprecated Use new layout components as GlobalPanel, Panel, PopUp and Snackbar
 * This will be removed in the next major version.
 */
@Component({
  imports: [ToolbarComponent, NgComponentOutlet],
  standalone: true,
  styleUrl: './drawer.component.scss',
  templateUrl: './drawer.component.html',
})
export class DrawerComponent<Component extends BaseDrawerContent<Return>, Return = unknown> extends BaseDrawer<Return> {
  private readonly _createComponentFn = inject(CREATE_COMPONENT_FN);
  protected readonly _injector = inject(Injector);
  title = input.required<string>();
  contentCmp = input.required<Type<Component>>();
  contentProps = input<Partial<DialogProps<Component>>>({});
  contentHost = viewChild<ElementRef<HTMLElement>>('contentHost');
  cmp = computed(() => {
    const host = this.contentHost()?.nativeElement;
    if (host) {
      return this._createComponentFn(this.contentCmp(), host, this.contentProps(), Injector.create({
        providers: [{
          provide: forwardRef(() => BaseDrawer),
          useValue: this
        }],
        parent: this._injector,
        name: 'DrawerContent injector'
      }));
    }
    return;
  });
  toolbarActions = computed(() => (this.cmp()?.instance as BaseDrawerContent<Return>).toolbarActions() ?? []);
  EToolbarPanelHeaderType = EToolbarPanelHeaderType;
  constructor() {
    super();
  }

  close() {
    this.onClose.emit(undefined as Return)
  }
}
