import { booleanAttribute, Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ELabelColor, ELabelMode, LabelComponent } from '../../atoms/label/label.component';
import { EProgressBarColor, EProgressBarMode, ProgressBarComponent } from '../../atoms/progress-bar/progress-bar.component';

export enum EAdminCourseCardMode {
	LIGHT = 'light',
	DARK = 'dark'
}

export enum EAdminCourseCardSize {
	SMALL = 'small',
	LARGE = 'large'
}

@Component({
  selector: 'admin-course-card',
  standalone: true,
  imports: [
    MatCardModule,
    MatIconModule,
    MatProgressBarModule,
    ImageComponent,
    LabelComponent,
    ProgressBarComponent,
		IconComponent
  ],
  templateUrl: './course-card.component.html',
  styleUrl: './course-card.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class CourseCardComponent {

	@Input() id: string = '';
	@Input() title: string = '';
	@Input() subtitle: string = '';
	@Input() image?: string;
	@Input() alt!: string;
	@Input() label: string = '';
	@Input() labelColor: ELabelColor = ELabelColor.BLACK;
	@Input() labelMode: ELabelMode = ELabelMode.LIGHT;
	@Input() icon?: EIconName;
	@Input() mode = EAdminCourseCardMode.LIGHT;
	@Input() size = EAdminCourseCardSize.LARGE;
	@Input() progressBarValue: number = 0;
	@Input() progressBarColor: EProgressBarColor = EProgressBarColor.SUCCESS;
	@Input({ transform: booleanAttribute }) skeleton!: boolean;
	@Input() skeletonItems!: number;


	imgError = false;
	ImgEntityType = ImgEntityType;
	ImgMode = EImgMode;
	ELabelColor = ELabelColor;
	ELabelMode = ELabelMode;
	EProgressBarColor = EProgressBarColor;
	EProgressBarMode = EProgressBarMode;
	EAdminCourseCardMode = EAdminCourseCardMode;

	@Output() cardClicked = new EventEmitter<Event>();

	handleClick(event: Event) {
		this.cardClicked.emit(event);
	}
	handleImageError() {
		this.imgError = !this.imgError;
	}
}
