import { ComponentType } from '@angular/cdk/overlay';
import { Injectable } from '@angular/core';
import { MatDialog, MatDialogRef } from '@angular/material/dialog';
import { EPopupMode, PopupComponent } from '../popup.component';
import { popupFactory } from '../popup.factory';

export interface IPopupConfig {
	title: string;
	description: string;
	actionButtonText: string;
	closeButtonText?: string;
	action: () => void;
	mode?: EPopupMode;
}

@Injectable({
	providedIn: 'root'
})
export class PopupService {

	constructor(
		private dialog: MatDialog
	) { }

	open(data: IPopupConfig): MatDialogRef<PopupComponent> {
		const dialogConfig = popupFactory(data);

		const popupRef = this.dialog.open(PopupComponent, dialogConfig);

		return popupRef;
	}

	openWithComponent<T>(component: ComponentType<T>, data: any = {}): MatDialogRef<T> {
		const dialogConfig = popupFactory(data);

		const dialogRef = this.dialog.open(component, dialogConfig);

		return dialogRef;
	}

}
