import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, EventEmitter, forwardRef, inject, Injector, Input, Output, ViewEncapsulation } from '@angular/core';
import {
	ControlContainer,
	ControlValueAccessor,
	FormControl,
	FormControlDirective,
	FormControlName,
	FormGroup,
	FormsModule,
	NG_VALUE_ACCESSOR,
	NgControl,
	NgModel,
	ReactiveFormsModule
} from "@angular/forms";
import { MatButtonModule } from "@angular/material/button";
import { ErrorStateMatcher } from '@angular/material/core';
import { MatIconModule } from "@angular/material/icon";
import { MatInputModule } from "@angular/material/input";
import { Subscription } from 'rxjs';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

interface Error {
  [key:string]: string | boolean;
}

export enum EInputMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum EInputType {
  NUMBER = 'number',
  TEXT = 'text',
  PASSWORD = 'password'
}

@Component({
  selector: 'admin-input',
  templateUrl: './input.component.html',
  styleUrls: ['./input.component.scss'],
  standalone: true,
  imports: [
    CommonModule,
    MatIconModule,
    MatInputModule,
    MatButtonModule,
    FormsModule,
    ReactiveFormsModule,
		IconComponent
  ],
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => InputComponent),
      multi: true,
    }
  ]
})
export class InputComponent implements ControlValueAccessor{

	@Input() mode: EInputMode = EInputMode.LIGHT;
  @Input({ transform: coerceBooleanProperty }) disabled: boolean = false;
  @Input() errorMessages!: Error;
  @Input() errorStateMatcher!: ErrorStateMatcher;
  @Input() hint = '';
  @Input() label = '';
  @Input() minlength: number | null = null;
  @Input() maxlength: number | null = null;
  @Input() name = '';
  @Input() placeholder = '';
  @Input() prefixIcon?: EIconName;
  @Input({ transform: coerceBooleanProperty }) readonly: boolean = false;
  @Input({ transform: coerceBooleanProperty }) required: boolean = false;
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;
  @Input() suffixIcon?: EIconName;	
	@Input() suffixText = '';
  @Input() type: EInputType = EInputType.TEXT;
  @Input() value = '';

  @Output() blur: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() change: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() focus: EventEmitter<FormControl> = new EventEmitter<FormControl>();

  //ControlvalueAccesor implementation
  private injector = inject(Injector);
  private subscription?: Subscription;
  control!: FormControl;

  ngOnInit() {
    const ngControl = this.injector.get(NgControl, null, { self: true, optional: true });

    if (ngControl instanceof NgModel) {
      this.control = ngControl.control;
      this.subscription = ngControl.control.valueChanges.subscribe((value) => {
        if (ngControl.model !== value || ngControl.viewModel !== value) {
          ngControl.viewToModelUpdate(value);
        }
      });
    } else if (ngControl instanceof FormControlDirective) {
      this.control = ngControl.control;
    } else if (ngControl instanceof FormControlName) {
      const container = this.injector.get(ControlContainer).control as FormGroup;
      if (ngControl.name && container.controls[ngControl.name]) {
        this.control = container.controls[ngControl.name] as FormControl;
      }
    } else {
      this.control = new FormControl();
    }
  }

  onChange: ((value: string) => void) | undefined;
  onTouched: (() => void) | undefined;

  writeValue(value: any) {
    this.value = value || '';
  }

  registerOnChange(fn: any) {
    this.onChange = fn;
  }

  registerOnTouched(fn: any) {
    this.onTouched = fn;
  }

  onBlur(): void {
    if (this.control) {
      this.control.markAsTouched();
      
      if (this.control.value) {
        const current = this.control.value.toString();
        const trimmed = current.trim();
        if (trimmed !== current) {
          this.control.setValue(trimmed);
          this.value = trimmed;
          if (this.onChange) {
            this.onChange(trimmed);
          }
        }

        if (this.maxlength && trimmed.length > this.maxlength) {
          this.control.setErrors({ ...this.control.errors, maxlength: true });
        } else {

          if (this.control.errors?.['maxlength']) {
            const { maxlength, ...otherErrors } = this.control.errors;
            this.control.setErrors(Object.keys(otherErrors).length > 0 ? otherErrors : null);
          }
        }
      } else {

        if (this.control.errors?.['maxlength']) {
          const { maxlength, ...otherErrors } = this.control.errors;
          this.control.setErrors(Object.keys(otherErrors).length > 0 ? otherErrors : null);
        }
      }
    }
    
    if (this.onTouched) {
      this.onTouched();
    }
    
    this.blur.emit(this.control);
  }

  ngOnDestroy() {
    this.subscription?.unsubscribe();
  }

}
