import { NgTemplateOutlet } from '@angular/common';
import { Component, computed, contentChildren, EventEmitter, input, Input, output, Output, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
import { MatToolbarModule } from '@angular/material/toolbar';
import { RouterLink } from '@angular/router';
import { EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { EProgressBarColor, EProgressMode, ProgressBarComponent } from '../../atoms/progress-bar/progress-bar.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';
import { EAdminMenuMode } from '../../buttons/menu/menu.component';
import { ToolbarActionDirective } from './toolbar-action.directive';
import { ToolbarExtraActionDirective } from './toolbar-extra-action.directive';

export interface IAdminToolbarBreadcrumb {
	breadcrumbType: EToolbarBreadcrumbType;
	text?: string;
	id?: string;
	routerLink?: string | any[];
	disabled?: boolean;
  ellipsisOptions?: IAdminMenuEllipsisOptions[];
}

export interface IAdminMenuEllipsisOptions {
	idEllipsisOptions: string;
	iconEllipsisOptions?: EIconName;
  textEllipsisOptions: string;
  disabledEllipsisOptions?: boolean;
}

export enum EToolbarPanelHeaderType {
	MAIN = 'main',
	PANEL = 'panel',
	DRAWER = 'drawer',
	CUSTOM = 'custom',
	SECONDARY = 'secondary'
}

export enum EToolbarBreadcrumbType {
	INACTIVE = 'inactive',
	LINK = 'link',
	ACTIVE = 'active',
	ELLIPSIS = 'ellipsis'
}

export enum EToolbarMode {
	LIGHT = 'light',
	DARK = 'dark'
}

type ToolbarActions =
	ToolbarActionDirective
	| ToolbarActionDirective[]
	| Readonly<ToolbarActionDirective>
	| Readonly<ToolbarActionDirective[]>;

	type ToolbarExtraActions =
	ToolbarExtraActionDirective
	| ToolbarExtraActionDirective[]
	| Readonly<ToolbarExtraActionDirective>
	| Readonly<ToolbarExtraActionDirective[]>;

@Component({
	imports: [
		ButtonComponent,
		MatToolbarModule,
		NgTemplateOutlet,
		MatIconModule,
		RouterLink,
		IconComponent,
		ImageComponent,
		ProgressBarComponent,
		MatMenuModule,
	],
	selector: 'admin-toolbar',
	standalone: true,
	styleUrl: './toolbar.component.scss',
	templateUrl: './toolbar.component.html',
	encapsulation: ViewEncapsulation.None,
})
export class ToolbarComponent {
	@Input() panelHeaderType = EToolbarPanelHeaderType.MAIN;
	@Input() title: string = '';
	@Input() tooltipButton: string = '';
	@Input() logoImgUrl: string | ImgEntityType = '';
	@Input() isLoading: boolean = false;
	@Input() breadcrumbs: IAdminToolbarBreadcrumb[] = [];
	@Input() routerLink?: string | any[] = '';
	@Input() mode: EToolbarMode = EToolbarMode.LIGHT;
	@Input() hasBorder: boolean = true;

	@Output() buttonClicked = new EventEmitter<Event>();
	@Output() menuButtonClicked = new EventEmitter<Event>();
	@Output() optionEllipsisClicked = new EventEmitter<IAdminMenuEllipsisOptions>();

	buttonButtonTypeDefault = EButtonButtonType.MATICONBUTTON;
	buttonColorDefault = EButtonColor.PRIMARY;
	buttonTypeDefault = EButtonType.SUBMIT;

	EToolbarPanelHeaderType = EToolbarPanelHeaderType;
	EToolbarBreadcrumbType = EToolbarBreadcrumbType;
	EButtonButtonType = EButtonButtonType;
	EButtonColor = EButtonColor;
	EButtonType = EButtonType;
	EToolbarMode = EToolbarMode;
	EButtonMode = EButtonMode;
	EIconName = EIconName;
	ImgEntityType = ImgEntityType;
	EProgressMode = EProgressMode;
	EProgressBarColor = EProgressBarColor;
	EAdminMenuMode = EAdminMenuMode;
	EIconMode = EIconMode;

	private static readonly cachedImgEntityTypes = Object.values(ImgEntityType);

	handleClick() {
		this.buttonClicked.emit();
	}
	menuButtonClick() {
		this.menuButtonClicked.emit();
	}
	openMenu(menuTrigger: MatMenuTrigger): void {
		menuTrigger.openMenu();
	}
	handleEllipsisOptionClick(option: IAdminMenuEllipsisOptions) {
    this.optionEllipsisClicked.emit(option);
  }

	isImgEntityType(value: string): value is ImgEntityType {
		return ToolbarComponent.cachedImgEntityTypes.includes(value as ImgEntityType);
	}

	actions = input<ToolbarActions>();
	protected contentActions = contentChildren<ToolbarActionDirective>(ToolbarActionDirective);

	toolbarActions = computed(() => {
		const actions = this.actions();
		if (!actions) { return this.contentActions().map(action => action.templateRef) }
		if (Array.isArray(actions)) {
			return actions.map(action => action.templateRef);
		}
		return [(actions as ToolbarActionDirective).templateRef]
	});

	extraActions = input<ToolbarExtraActions>();
	protected contentExtraActions = contentChildren<ToolbarExtraActionDirective>(ToolbarExtraActionDirective);
	
	toolbarExtraActions = computed(() => {
		const extraActions = this.extraActions();
		if (!extraActions) { return this.contentExtraActions().map(extraAction => extraAction.templateRef) }
		if (Array.isArray(extraActions)) {
			return extraActions.map(extraAction => extraAction.templateRef);
		}
		return [(extraActions as ToolbarExtraActionDirective).templateRef]
	});

	closeClicked = output<void>();

}

