import { Component, EventEmitter, Input, Output, ViewChild, ViewEncapsulation } from '@angular/core';
import { MatDrawer, MatDrawerContainer, MatDrawerContent } from '@angular/material/sidenav';
import { EIconName } from '../../atoms/icon/icon.component';

export enum EPanelMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-panel',
	standalone: true,
	imports: [
		MatDrawerContainer,
		MatDrawer,
		MatDrawerContent,
	],
	templateUrl: './panel.component.html',
	styleUrl: './panel.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class PanelComponent {

	@Input() opened = false;
	@Input() openingMode: 'over' | 'push' | 'side' = 'over';
	@Input() hasBackdrop = false;
	@Input() position: 'start' | 'end' = 'end';
	@Input() autoFocus = true;
	@Input() width: string = '';
	@Input() mode = EPanelMode.LIGHT;
	@Input() fixedInViewport = false;

	@Output() keyDownEscape = new EventEmitter<void>();
	@Output() closedStart = new EventEmitter<void>();
	@Output() openedChange = new EventEmitter<boolean>();
	@Output() openedStart = new EventEmitter<void>();

	@ViewChild(MatDrawer) adminDrawerRef!: MatDrawer;

	EIconName = EIconName;
	
	toggle() {
		this.adminDrawerRef.toggle();
	}
}
