import { Component, Input, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { IconComponent } from '../../atoms/icon/icon.component';

export enum ELabelColor {
  PRIMARY = 'primary',
  ACCENT = 'accent',
  WARN = 'warn',
  SUCCESS = 'success',
  EXTRA = 'extra',
  ALERT = 'alert',
	BLACK = 'black',
}

export enum ELabelMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-label',
  standalone: true,
  imports: [
    MatIconModule,
    IconComponent
  ],
  templateUrl: './label.component.html',
  styleUrl: './label.component.scss',
  encapsulation: ViewEncapsulation.None
})

export class LabelComponent {
	@Input() mode: ELabelMode = ELabelMode.LIGHT;
  @Input() id?: string;
  @Input() text: string = 'Label';
  @Input() color = ELabelColor.PRIMARY;
}
