import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, ElementRef, EventEmitter, forwardRef, inject, Injector, Input, OnDestroy, OnInit, Output, ViewChild, ViewEncapsulation } from '@angular/core';
import {
	ControlContainer,
	ControlValueAccessor,
	FormControl,
	FormControlDirective,
	FormControlName,
	FormGroup,
	FormsModule,
	NG_VALUE_ACCESSOR,
	NgControl,
	NgModel,
	ReactiveFormsModule
} from "@angular/forms";
import { MatAutocompleteModule, MatAutocompleteSelectedEvent } from '@angular/material/autocomplete';
import { ErrorStateMatcher } from '@angular/material/core';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { debounceTime, distinctUntilChanged, Subject, Subscription } from 'rxjs';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

export interface IAutocompleteOption {
  id: string;
  text: string;
  disabled?: boolean;
}

interface Error {
  [key: string]: string | boolean;
}

export enum EAutocompleteMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-autocomplete',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatAutocompleteModule,
    MatInputModule,
    MatIconModule,
		IconComponent
  ],
  templateUrl: './autocomplete.component.html',
  styleUrl: './autocomplete.component.scss',
  encapsulation: ViewEncapsulation.None,
  host: { 'class': 'admin-autocomplete' },
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => AutocompleteComponent),
      multi: true,
    }
  ]
})
export class AutocompleteComponent implements ControlValueAccessor, OnInit, OnDestroy {
  
  @ViewChild('autocompleteInput') autocompleteInput!: ElementRef<HTMLInputElement>;

  @Input() mode: EAutocompleteMode = EAutocompleteMode.LIGHT;
  @Input() options: IAutocompleteOption[] = [];
  @Input() label = '';
  @Input() placeholder = '';
  @Input() hint = '';
  @Input() errorMessages!: Error;
  @Input() errorStateMatcher!: ErrorStateMatcher;
  @Input({ transform: coerceBooleanProperty }) required: boolean = false;
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;
  @Input() prefixIcon?: EIconName;
  @Input() suffixIcon?: EIconName;
  @Input() delay = 0;
  @Input() value: IAutocompleteOption | string = '';
  
  @Output() optionSelected = new EventEmitter<IAutocompleteOption>();
	@Output() blur: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() change: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() focus: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  
  @Output() prefixIconClick = new EventEmitter<void>();
  @Output() suffixIconClick = new EventEmitter<void>();
  
  private inputSubject = new Subject<string>();
  private subscription!: Subscription;
  private injector = inject(Injector);
  control!: FormControl;
  
  EAutocompleteMode = EAutocompleteMode;
  
  // Function to display the option text in the input
  displayFn = (option: IAutocompleteOption): string => {
    return option ? option.text : '';
  };
  
  // Helper method to get display text from value
  getDisplayText(value: IAutocompleteOption | string): string {
    if (typeof value === 'string') {
      return value;
    }
    return value ? value.text : '';
  }
  
  ngOnInit() {
    const ngControl = this.injector.get(NgControl, null, { self: true, optional: true });

    if (ngControl instanceof NgModel) {
      this.control = ngControl.control;
      this.subscription = ngControl.control.valueChanges.subscribe((value) => {
        if (ngControl.model !== value || ngControl.viewModel !== value) {
          ngControl.viewToModelUpdate(value);
        }
      });
    } else if (ngControl instanceof FormControlDirective) {
      this.control = ngControl.control;
    } else if (ngControl instanceof FormControlName) {
      const container = this.injector.get(ControlContainer).control as FormGroup;
      if (ngControl.name && container.controls[ngControl.name]) {
        this.control = container.controls[ngControl.name] as FormControl;
      }
    } else {
      this.control = new FormControl(this.value);
    }
    
    // Setup input debouncing
    this.subscription = this.inputSubject
      .pipe(
        debounceTime(this.delay),
        distinctUntilChanged()
      )
      .subscribe(value => {
        this.onChange?.(value);
        this.change.emit(this.control);
      });
  }
  
  ngOnDestroy() {
    this.subscription?.unsubscribe();
  }
  
  onOptionSelected(event: MatAutocompleteSelectedEvent) {
    const selectedOption: IAutocompleteOption = event.option.value;
    this.optionSelected.emit(selectedOption);
    this.value = selectedOption;
    this.control.setValue(selectedOption, { emitEvent: false });
    this.onChange?.(selectedOption);
  }
  
  onInputChange(event: Event) {
    const inputElement = event.target as HTMLInputElement;
    const inputValue = inputElement.value;
    this.inputSubject.next(inputValue);
  }
  
  // ControlValueAccessor implementation
  onChange: ((value: IAutocompleteOption | string) => void) | undefined;
  onTouched: (() => void) | undefined;
  
  writeValue(value: any) {
    this.value = value || '';
    if (this.control) {
      this.control.setValue(value, { emitEvent: false });
    }
  }
  
  registerOnChange(fn: any) {
    this.onChange = fn;
  }
  
  registerOnTouched(fn: any) {
    this.onTouched = fn;
  }

  onPrefixIconClick(event: Event) {
    event.stopPropagation();
    this.prefixIconClick.emit();
  }

  onSuffixIconClick(event: Event) {
    event.stopPropagation();
    this.suffixIconClick.emit();
  }
}
