import { Component, EventEmitter, Input, Output, ViewEncapsulation, booleanAttribute } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';

export enum EPanelCardMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-panel-card',
  standalone: true,
  imports: [
    MatCardModule,
    ImageComponent,
    IconComponent
  ],
  templateUrl: './panel-card.component.html',
  styleUrl: './panel-card.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class PanelCardComponent {
  @Input() id!: string;
  @Input() mode = EPanelCardMode.LIGHT;
  @Input() title!: string;
  @Input() description!: string;
  @Input() image!: string;
  @Input() alt!: string;
  @Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;

  imgError = false;
  ImgEntityType = ImgEntityType;
  ImgMode = EImgMode;
	EPanelCardMode = EPanelCardMode;
	EIconName = EIconName;

  @Output() cardClicked = new EventEmitter<Event>();

  handleClick() {
    this.cardClicked.emit(new Event(this.id));
  }
  handleImageError() {
    this.imgError = !this.imgError;
  }
}
