import { Directive, ElementRef, HostListener } from '@angular/core';

@Directive({
  selector: 'mat-form-field[adjustPanelHeight]',
  standalone: true,
})
export class AdjustPanelHeightDirective {
  constructor(
    private elementRef: ElementRef
  ) {}

  @HostListener('click', ['$event'])
  onClick(event: MouseEvent) {
    this.adjustPanelHeight();
  }

  private adjustPanelHeight(): void {
    const wrapper = this.elementRef.nativeElement as HTMLElement;

    if (wrapper) {
      const wrapperRect = wrapper.getBoundingClientRect();
      const viewportHeight = window.innerHeight;
      const middleOfScreen = viewportHeight / 2;
      const willOpenUpward = wrapperRect.top > middleOfScreen;
      let availableSpace;
      if (willOpenUpward) {
        availableSpace = wrapperRect.top;
      } else {
        availableSpace = viewportHeight - wrapperRect.bottom;
      }
      const select = wrapper.querySelector('mat-select') as HTMLElement;
      if (select) {
        setTimeout(() => {
          const panel = document.querySelector('.admin-select-panel') as HTMLElement;
          if (panel) {
            panel.style.maxHeight = `${availableSpace * 0.8}px`;
          }
        }, 0);
      }
    }
  }
}
