import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, EventEmitter, forwardRef, Input, Output, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, FormControl, FormsModule, NG_VALUE_ACCESSOR, ReactiveFormsModule, ValidatorFn, Validators } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';

export enum ETextareaMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-textarea',
  templateUrl: './textarea.component.html',
  styleUrls: ['./textarea.component.scss'],
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatIconModule
  ],
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => TextareaComponent),
      multi: true
    },
  ]
})
export class TextareaComponent implements ControlValueAccessor {

  // inputs
  @Input() mode: ETextareaMode = ETextareaMode.LIGHT;
  @Input() errorMessages: { [key: string]: string } = {};
  @Input() hint = '';
  @Input() label = '';
  @Input() placeholder = '';
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;
  
  @Input()
  set disabled(value: boolean) {
    this._disabled = value;
    if (value) {
      this.formControl.disable();
    } else {
      this.formControl.enable();
    }
  }
  get disabled(): boolean {
    return this._disabled;
  }

  @Input() 
  set required(value: boolean) {
    this._required = value;
    this.updateValidators();
  }
  get required(): boolean {
    return this._required;
  }

  @Input() 
  set minlength(value: number | null) {
    this._minlength = value;
    this.updateValidators();
  }
  get minlength(): number | null {
    return this._minlength;
  }

  @Input() 
  set maxlength(value: number | null) {
    this._maxlength = value;
    this.updateValidators();
  }
  get maxlength(): number | null {
    return this._maxlength;
  }

  @Input() 
  set validators(validatorFns: ValidatorFn[]) {
    this._customValidators = validatorFns;
    this.updateValidators();
  }

  @Input() 
  set value(val: string) {
    this._value = val;
    if (this.formControl) {
      this.formControl.setValue(val || '', { emitEvent: false });
    }
  }
  get value(): string {
    return this._value;
  }

  // outputs
  @Output() blur: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() change: EventEmitter<FormControl> = new EventEmitter<FormControl>();
  @Output() focus: EventEmitter<FormControl> = new EventEmitter<FormControl>();

  // properties
  formControl = new FormControl('');

  private _disabled = false;
  private _customValidators: ValidatorFn[] = [];
  private _required = false;
  private _minlength: number | null = null;
  private _maxlength: number | null = null;
  private _value = '';
  onChange = (_: any) => {};
  onTouched = () => {};

  // constructor
  constructor() {}

  // public methods
  onInputChange(event: any): void {
    const value = event.target.value;
    this._value = value || '';
    this.onTouched();
    this.onChange(value);
    this.change.emit(this.formControl);
  }

  onBlur(): void {
    const current = typeof this.formControl.value === 'string' ? this.formControl.value : '';
    const trimmed = current.trim();
    if (trimmed !== current) {
      this._value = trimmed
      this.formControl.setValue(trimmed);
    }
    this.onTouched();
    this.blur.emit(this.formControl);
    this.formControl.updateValueAndValidity();
  }

  getErrorMessage(): string {
    const errors = this.formControl.errors;
    if (errors) {
      const firstError = Object.keys(errors)[0];
      return this.errorMessages[firstError] || '';
    }
    return '';
  }

  hasError(): boolean {
    return this.formControl.touched && this.formControl.invalid;
  }

  // control value accessor implementation
  writeValue(value: any): void {
    this._value = value || '';
    this.formControl.setValue(value || '', { emitEvent: false });
  }

  registerOnChange(fn: any): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: any): void {
    this.onTouched = fn;
  }

  // private methods
  private updateValidators(): void {
    const validators = [...this._customValidators];
    
    if (this._required) {
      validators.push(Validators.required);
    }
    
    if (this._minlength !== null && this._minlength > 0) {
      validators.push(Validators.minLength(this._minlength));
    }
    
    if (this._maxlength !== null && this._maxlength > 0) {
      validators.push(Validators.maxLength(this._maxlength));
    }
    
    this.formControl.setValidators(validators);
    this.formControl.updateValueAndValidity();
  }

}
