import { ChangeDetectionStrategy, Component, inject, Input } from '@angular/core';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { EIconName } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';

export enum EPopupMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-popup',
	standalone: true,
	imports: [
		ButtonComponent
	],
	templateUrl: './popup.component.html',
	styleUrl: './popup.component.scss',
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PopupComponent {
	readonly popup = inject(MAT_DIALOG_DATA);

	constructor(private dialogRef: MatDialogRef<PopupComponent>) { }

	@Input() mode = this.popup.mode || EPopupMode.LIGHT;

	EButtonColor = EButtonColor;
	EButtonType = EButtonType;
	EButtonButtonType = EButtonButtonType;
	EButtonMode = EButtonMode;
	EPopupMode = EPopupMode;
	EIconName = EIconName;

	actionButtonClicked() {
		if (this.popup.action) {
			this.popup.action();
		}
	}

	close() {
		this.dialogRef.close();
	}
}
