import { Component, EventEmitter, forwardRef, Input, Output, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';
import { MatCheckboxChange, MatCheckboxModule } from '@angular/material/checkbox';

export enum ECheckboxMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export interface ICheckboxOption {
  checked: boolean;
  disabled?: boolean;
  id?: string;
  labelPosition?: string;
  name: string;
  required: boolean;
  value: string;
  label: string;
}
export enum ECheckboxLabelPosition {
  BEFORE = 'before',
  AFTER = 'after'
}
@Component({
  selector: 'admin-checkbox',
  standalone: true,
  imports: [MatCheckboxModule],
  templateUrl: './checkbox.component.html',
  styleUrls: ['./checkbox.component.scss'],
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => CheckboxComponent),
      multi: true
    }
  ]
})
export class CheckboxComponent implements ControlValueAccessor {
  @Input() mode: ECheckboxMode = ECheckboxMode.LIGHT;
  @Input() disabled: boolean = false;
  @Input() id: string = '';
  @Input() label: string = '';
  @Input() labelPosition = ECheckboxLabelPosition.AFTER;
  @Input() name: string = '';
  @Input() required: boolean = false;
  @Output() checkboxChange: EventEmitter<MatCheckboxChange> = new EventEmitter<MatCheckboxChange>();

  value: boolean = false;

  onChange: any = () => {};
  onTouched: any = () => {};

  writeValue(value: boolean): void {
    this.value = value;
  }

  registerOnChange(fn: any): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: any): void {
    this.onTouched = fn;
  }

  setDisabledState?(isDisabled: boolean): void {
    this.disabled = isDisabled;
  }

  onCheckboxChange(event: MatCheckboxChange): void {
    this.value = event.checked;
    this.onChange(this.value);
    this.onTouched();
    this.checkboxChange.emit(event);
  }
}