import { Component, EventEmitter, Input, Output } from '@angular/core';
import { RouterLink } from '@angular/router';

export enum ELinkTextMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-link-text',
  standalone: true,
  imports: [
		RouterLink,
	],
  templateUrl: './link-text.component.html',
  styleUrl: './link-text.component.scss'
})
export class LinkTextComponent {
  @Input() id: string = '';
  @Input() text: string = '';
	@Input() mode = ELinkTextMode.LIGHT;
	@Input() routerLink?: string | any[];

	@Output() buttonClicked = new EventEmitter<Event>();

  handleClick() {
    this.buttonClicked.emit();
  }
}
