import { booleanAttribute, Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ImgEntityType } from '../../atoms/image/image.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonType } from '../../buttons/button/button.component';
import { EFloatingActionButtonMode, FloatingActionButtonComponent, IFloatingActionButtonOption } from '../../buttons/floating-action-button/floating-action-button.component';

export enum EPhotoBrowserUse {
  AUDIO = 'audio',
  DEFAULT = 'default',
  DOC = 'doc',
  ELEARNING = 'elearning',
  EXCEL = 'excel',
  GROUP = 'group',
  IMAGE = 'image',
  NEWSLETTER = 'newsletter',
  PDF = 'PDF',
  POWERPOINT = 'powerpoint',
  PROFILE = 'profile',
  VIDEO = 'video',
  WORD = 'word',
  ZIP = 'ZIP'
}

export enum EPhotoBrowserShape {
  SQUARE = 'square',
  CIRCLE = 'circle'
}

export enum EPhotoBrowserButtonPosition {
  INSIDE = 'inside',
  OUTSIDE = 'outside'
}

export enum EPhotoBrowserButtonIcon {
	EDIT = EIconName.EDIT,
	DELETE = EIconName.CLOSE
}

export enum EPhotoBrowserMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-photo-browser',
  standalone: true,
  imports: [
    ButtonComponent,
    IconComponent,
		FloatingActionButtonComponent
  ],
  templateUrl: './photo-browser.component.html',
  styleUrl: './photo-browser.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class PhotoBrowserComponent {

  @Input() alt?: string;
  @Input() buttonDisabled!: boolean;
  @Input() buttonIcon: EIconName = EIconName.EDIT;
  @Input() buttonId?: string;
  @Input() buttonTooltip?: string;
  @Input() buttonTooltipEdit?: string;
  @Input() buttonTooltipClose?: string;
  @Input() height: number = 160;
  @Input() id?: string;
  @Input() image?: string | undefined;
  @Input() shape: EPhotoBrowserShape = EPhotoBrowserShape.SQUARE;
  @Input() buttonPosition: EPhotoBrowserButtonPosition = EPhotoBrowserButtonPosition.INSIDE;
  @Input() use: EPhotoBrowserUse = EPhotoBrowserUse.DEFAULT;
  @Input() width: number = 160;
  @Input() mode: EPhotoBrowserMode = EPhotoBrowserMode.LIGHT;
  @Input() helperText?: string;
	@Input() options: IFloatingActionButtonOption[] = [];
	@Input({ transform: booleanAttribute }) readonly: boolean = false;

	@Output() optionClicked = new EventEmitter<IFloatingActionButtonOption>();
  @Output() buttonClicked = new EventEmitter<void>();

  imgError = false;
  ImgEntityType = ImgEntityType;
  buttonTypeDefault = EButtonType.BUTTON;
  EButtonButtonType = EButtonButtonType;
	EButtonColor = EButtonColor;
  buttonColorDefault = EButtonColor.ACCENT;
  EPhotoBrowserUse = EPhotoBrowserUse;
  EPhotoBrowserButtonIcon = EPhotoBrowserButtonIcon;
  EPhotoBrowserShape = EPhotoBrowserShape;
	EIconName = EIconName;
	EFloatingActionButtonMode = EFloatingActionButtonMode;
	EPhotoBrowserMode = EPhotoBrowserMode;

  handleImageError() {
    this.imgError = !this.imgError;
  }

  getIconByUse(): EIconName {
    switch (this.use) {
      case EPhotoBrowserUse.PROFILE:
        return EIconName.FACE;
      case EPhotoBrowserUse.NEWSLETTER:
        return EIconName.IMAGE;
      case EPhotoBrowserUse.GROUP:
        return EIconName.PEOPLE;
      case EPhotoBrowserUse.ELEARNING:
        return EIconName.SCHOOL;
      case EPhotoBrowserUse.IMAGE:
        return EIconName.IMAGE;
      case EPhotoBrowserUse.AUDIO:
        return EIconName.HEADPHONES;
      case EPhotoBrowserUse.DOC:
        return EIconName.DESCRIPTION;
      case EPhotoBrowserUse.PDF:
        return EIconName.CUSTOM_PDF;
      case EPhotoBrowserUse.ZIP:
        return EIconName.FOLDER_ZIP;
      case EPhotoBrowserUse.VIDEO:
        return EIconName.ONDEMAND_VIDEO;
      case EPhotoBrowserUse.EXCEL:
        return EIconName.CUSTOM_EXCEL;
      case EPhotoBrowserUse.WORD:
        return EIconName.CUSTOM_WORD;
      case EPhotoBrowserUse.POWERPOINT:
        return EIconName.CUSTOM_POWERPOINT;
      default:
        return EIconName.IMAGE;
    }
  }
}
