import { NgClass } from '@angular/common';
import { Component, Input, ViewEncapsulation, booleanAttribute } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatIconModule } from '@angular/material/icon';
import { EIconColor, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';

export enum EKpiCardColor {
	WHITE = 'white',
	ACCENT = 'accent',
	SECONDARY = 'secondary',
	WARN = 'warn',
	SUCCESS = 'success',
	PURPLE = 'purple',
	ALERT = 'alert'
}

export enum EKpiCardMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
	selector: 'admin-kpi-card',
	standalone: true,
	imports: [
		MatCardModule,
		NgClass,
		MatIconModule,
		IconComponent,
		ImageComponent
	],
	templateUrl: './kpi-card.component.html',
	styleUrl: './kpi-card.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class KpiCardComponent {

	@Input() id: string = '';
	@Input() mode = EKpiCardMode.LIGHT;
	@Input() title: string = '';
	@Input() subtitle: string = '';
	@Input() color?: EKpiCardColor;
	@Input() image?: string;
	@Input() alt: string = '';
	@Input() icon?: EIconName;
	@Input() iconColor = EIconColor.PRIMARY;
	@Input({ transform: booleanAttribute }) skeleton!: boolean;
	@Input() skeletonItems!: number;

	imgError = false;
	ImgEntityType = ImgEntityType;
	ImgMode = EImgMode;
	EKpiCardMode = EKpiCardMode;
	EIconName = EIconName;

	handleImageError() {
		this.imgError = true;
	}

}
