import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { EIconName } from '../../atoms/icon/icon.component';
import { ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../../buttons/button/button.component';
import { ChipGroupComponent } from '../../forms/chip-group/chip-group.component';
import { EChipGroupMode, IAdminChipGroup } from '../types/chip-group.types';

export enum EMessageInputMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum EMessageInputType {
  DEFAULT = 'default',
  STRETCH = 'stretch',
  IA_THINKING = 'iaThinking'
}

@Component({
  selector: 'admin-message-input',
  standalone: true,
  imports: [
    MatFormFieldModule,
    MatInputModule,
    MatIconModule,
    ButtonComponent,
    ChipGroupComponent,
    ImageComponent,
  ],
  templateUrl: './message-input.component.html',
  styleUrl: './message-input.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class MessageInputComponent {

  @Input() messageInputType = EMessageInputType.DEFAULT;
  @Input() disabled = false;
  @Input() mode = EMessageInputMode.LIGHT;
  @Input() placeholder = '';
  @Input() iconLeftButton?: EIconName;
  @Input() iconRightButton?: EIconName;
  @Input() idLeftButton: string = '';
  @Input() idRightButton: string = '';
  @Input() tooltipLeftButton: string = '';
  @Input() tooltipRightButton: string = '';
  @Input() disabledRightButton = true;
	@Input() chips: IAdminChipGroup[] = [];

  @Output() messageInputBlur = new EventEmitter<string>();
  @Output() messageInputFocus = new EventEmitter<string>();
  @Output() messageInputInput = new EventEmitter<string>();  
  @Output() leftIconButtonClicked = new EventEmitter<string>();
  @Output() rightIconButtonClicked = new EventEmitter<string>();

  /** Event emitted when a chip is removed */
  @Output() removedChip = new EventEmitter<IAdminChipGroup>();
  /** Event emitted when a chip is clicked */
  @Output() clickedChip = new EventEmitter<IAdminChipGroup>();

	onTextareaInput(value: string): void {
    this.disabledRightButton = !value.trim();
    this.messageInputInput.emit(value);
  }
	
  EIconName = EIconName;
  EButtonType = EButtonType;
  EButtonButtonType = EButtonButtonType;
  EButtonColor = EButtonColor;
  EMessageInputMode = EMessageInputMode;
  EButtonMode = EButtonMode;
  EMessageInputType = EMessageInputType;
  EChipGroupMode = EChipGroupMode;
  ImgEntityType = ImgEntityType;
}