import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
import { MatTooltip } from "@angular/material/tooltip";
import { EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonSize, EButtonType } from '../button/button.component';

export interface IAdminMenuOption {
	id?: string;
	text?: string;
	disabled?: boolean;
	visible?: boolean;
	hasCheckIcon?: boolean;
  intro?: string;
  icon?: EIconName;
  divider?: boolean;
  actionIcon?: EIconName;
  actionIconTooltip?:string;
	action?: (option: IAdminMenuOption) => void;
	iconAction?: (option: IAdminMenuOption) => void;
}

export enum EAdminMenuMode {
	LIGHT = 'light',
	DARK = 'dark'
}

@Component({
  selector: 'admin-menu',
  standalone: true,
  imports: [
    MatMenuModule,
    ButtonComponent,
    MatIconModule,
    IconComponent,
    CommonModule,
    MatTooltip
],
  templateUrl: './menu.component.html',
  styleUrl: './menu.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class MenuComponent {

  @Input() options: IAdminMenuOption[] = [];
  @Input() buttonType = EButtonButtonType.MATBUTTON;
  @Input() id: string = '';
  @Input() type = EButtonType.BUTTON;
  @Input() color = EButtonColor.PRIMARY;
  @Input() size = EButtonSize.LARGE;
  @Input() text: string = '';
  @Input() leftIcon?: EIconName;
  @Input() rightIcon?: EIconName;
  @Input() disabled: boolean = false;
  @Input() mode = EAdminMenuMode.LIGHT;

  @Output() optionClicked = new EventEmitter<IAdminMenuOption>();
  @Output() optionActionClicked = new EventEmitter<IAdminMenuOption>();

  EButtonMode = EButtonMode;
  EAdminMenuMode = EAdminMenuMode;
  EIconMode = EIconMode;
	EIconName = EIconName;

  handleClick(option: IAdminMenuOption) {
		if (option.action) {
			option.action(option);
		}
    this.optionClicked.emit(option);
  }

  handleActionIconClick(option: IAdminMenuOption, event: Event) {
    if (option.iconAction) {
      event.stopPropagation();
      option.iconAction(option);
      this.optionActionClicked.emit(option);
    }
  }

  openMenu(menuTrigger: MatMenuTrigger): void {
    if (this.disabled) {
      menuTrigger.closeMenu();
    } else {
      menuTrigger.openMenu();
    }
  }
}
