import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatRippleModule } from '@angular/material/core';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule } from '@angular/material/menu';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

export enum ESplitButtonColor{
  PRIMARY = 'primary',
  ACCENT = 'accent',
}
export enum ESplitButtonStatus{
  ENABLED = 'enabled',
  DISABLED = 'disabled',
  AWAITING = 'awaiting',
}

export enum ESplitButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

// Propiedades comunes reutilizables
interface ISplitButtonCommonProps {
	disabled?: boolean;
	divider?: boolean;
	id: string;
	text: string;
	action?: () => void;
}

// Caso con icono (iconFontFamily obligatorio)
interface ISplitButtonWithIcon extends ISplitButtonCommonProps {
	icon: EIconName;
}

// Caso sin icono (iconFontFamily no permitida)
interface ISplitButtonWithoutIcon extends ISplitButtonCommonProps {
	icon?: undefined;
}

// Interface para la opción de split button
export type ISplitButtonOption = ISplitButtonWithIcon | ISplitButtonWithoutIcon;

@Component({
  selector: 'admin-split-button',
  standalone: true,
  imports: [
    CommonModule, 
    MatButtonModule, 
    MatIconModule, 
    MatMenuModule, 
    MatRippleModule,
		IconComponent
  ],
  templateUrl: './split-button.component.html',
  styleUrl: './split-button.component.scss',
  host: {'class': 'admin-split-button'},
  encapsulation: ViewEncapsulation.None
})
export class SplitButtonComponent {
  @Input() color = ESplitButtonColor.ACCENT;
  @Input() label = 'label';
  @Input() options: ISplitButtonOption[] = [];
  @Input() waitingStateLabel = 'Waiting';
  @Input() status = ESplitButtonStatus.ENABLED;
  @Input() mode = ESplitButtonMode.LIGHT;
	@Input() leftIcon?: EIconName;
	
  @Output() onBtnClick = new EventEmitter<Event>();
  @Output() onDropdownClick = new EventEmitter<ISplitButtonOption>();

	EIconName = EIconName;

	handleClick(option: ISplitButtonOption) {
		if (option.action) {
			option.action();
		}
    this.onDropdownClick.emit(option);
  }

}
