import {
	ApplicationRef,
	ComponentRef,
	EnvironmentInjector,
	InjectionToken,
	Injector,
	Type,
	createComponent,
	inject
} from '@angular/core';

export type createComponentFn<T = unknown> = (
	component: Type<T>,
	hostElem: HTMLElement,
	props: Partial<T>,
	injector?: Injector
) => ComponentRef<T>;

export const CREATE_COMPONENT_FN = new InjectionToken<createComponentFn>(
	'Create component function',
	{
		providedIn: 'root',
		factory: () => {
			const appRef = inject(ApplicationRef);
			return (cmp, host, props = {}, inject?) => {
				const cmpRef = loadComponent({
					type: cmp,
					environmentInjector: appRef.injector,
					hostElement: host,
					elementInjector: inject ?? appRef.injector
				});
				for (const [key, value] of Object.entries(props)) {
					cmpRef.setInput(key, value);
				}
				appRef.attachView(cmpRef.hostView);
				return cmpRef;
			};
		},
	}
);

type Props<K, T extends Type<K>> = {
	type: T,
	environmentInjector: EnvironmentInjector,
	hostElement?: Element,
	elementInjector?: Injector
}

function loadComponent<K, T extends Type<K>>({ type, environmentInjector, hostElement, elementInjector }: Props<K, T>): ComponentRef<K> {
	try {
		return createComponent(type, { environmentInjector, hostElement, elementInjector });
	} catch (ex) {
		return createComponent(
			(type as unknown as () => T)(),
			{ environmentInjector, hostElement, elementInjector });
	}
}