import { Component, EventEmitter, Input, Output, ViewEncapsulation, booleanAttribute } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { EIconColor, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { EProgressBarColor, EProgressBarMode, ProgressBarComponent } from '../../atoms/progress-bar/progress-bar.component';
import { EButtonButtonType, EButtonColor } from '../../buttons/button/button.component';
import { EAdminMenuMode, IAdminMenuOption, MenuComponent } from '../../buttons/menu/menu.component';
import { ETextButtonMode, ETextButtonType, TextButtonComponent } from '../../buttons/text-button/text-button.component';

export enum EGridCardState {
  ACTIVE = 'active',
  INACTIVE = 'inactive',
  WARN = 'warn'
}

export enum EGridCardMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-grid-card',
  standalone: true,
  imports: [
		MatIconModule,
    IconComponent,
    MenuComponent,
    ImageComponent,
    TextButtonComponent,
    ProgressBarComponent
	],
  templateUrl: './grid-card.component.html',
  styleUrl: './grid-card.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class GridCardComponent {
	
	@Input() id: string = '';
  @Input() title: string = '';
  @Input() subtitle: string = '';
  @Input() image?: string | ImgEntityType;
  @Input() alt?: string;
  @Input() state?: EGridCardState;
  @Input() leftIcon?: EIconName;
  @Input() rightIcon?: EIconName;
  @Input() options: IAdminMenuOption[] = [];
  @Input() leftFooterText: string = '';
  @Input() rightFooterText: string = '';
  @Input({ transform: booleanAttribute }) skeleton!: boolean;
  @Input() skeletonItems!: number;
  @Input() mode: EGridCardMode = EGridCardMode.LIGHT;
  @Input() textButton: string = '';
  @Input() iconButton?: EIconName;
	@Input() progressBarValue: number = 0;
	@Input() progressBarColor: EProgressBarColor = EProgressBarColor.SUCCESS;
	@Input() progressBarText: string = '';

  @Output() buttonClicked = new EventEmitter<Event>();
  @Output() optionClicked = new EventEmitter<IAdminMenuOption>();
  @Output() textButtonClicked = new EventEmitter<void>();

  imgError = false;
  ImgEntityType = ImgEntityType;
  ImgMode = EImgMode;
  EMenuMode = EAdminMenuMode;
  EIconName = EIconName;
  ETextButtonType = ETextButtonType;
  ETextButtonMode = ETextButtonMode;
	EProgressBarColor = EProgressBarColor;
	EProgressBarMode = EProgressBarMode;

  buttontype = EButtonButtonType.MATICONBUTTON;
  color = EButtonColor.PRIMARY;

  EIconColor = EIconColor;
  EGridCardState = EGridCardState;
  EGridCardMode = EGridCardMode;

  handleClick(event: Event) {
    this.buttonClicked.emit(event);
  }
  handleImageError() {
    this.imgError = !this.imgError;
  }

  isImgEntityType(value: string | ImgEntityType | undefined): value is ImgEntityType {
    if (!value) return false;
    return Object.values(ImgEntityType).includes(value as ImgEntityType);
  }
}
