import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';

export enum ETextButtonMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export enum ETextButtonType {
  BUTTON = 'button',
  SUBMIT = 'submit',
  RESET = 'reset'
}

export enum ETextButtonSize {
  SMALL = 'small',
  DEFAULT = 'default'
}

@Component({
  selector: 'admin-text-button',
  standalone: true,
  imports: [
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    IconComponent
  ],
  templateUrl: './text-button.component.html',
  styleUrl: './text-button.component.scss',
  encapsulation: ViewEncapsulation.None
})
export class TextButtonComponent {

  @Input() id: string = '';
  @Input() text: string = '';
  @Input() type = ETextButtonType.BUTTON;
  @Input() size: ETextButtonSize = ETextButtonSize.DEFAULT;
  @Input() tooltip: string = '';
  @Input() disabled: boolean = false;
  @Input() icon?: EIconName;
  @Input() mode: ETextButtonMode = ETextButtonMode.LIGHT;

  @Output() buttonClicked = new EventEmitter<Event>();

  handleClick() {
    this.buttonClicked.emit();
  }
}
