import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, computed, ElementRef, EventEmitter, Input, Output, QueryList, ViewChildren, ViewEncapsulation } from '@angular/core';
import { ControlValueAccessor, FormControl, FormsModule, NG_VALUE_ACCESSOR, ReactiveFormsModule, ValidatorFn, Validators } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectChange, MatSelectModule } from '@angular/material/select';
import { MatTooltipModule } from '@angular/material/tooltip';
import { AdjustPanelHeightDirective } from './adjust-panel-height.directive';

export enum ESelectMode {
  LIGHT = 'light',
  DARK = 'dark'
}

export interface ISelectOption {
  id?: string;
  value: string;
  viewValue: string;
  disabled?: boolean
}
@Component({
  selector: 'admin-select',
  standalone: true,
  imports: [
    CommonModule,
    MatFormFieldModule,
    MatSelectModule,
    MatInputModule,
    MatTooltipModule,
    FormsModule,
    ReactiveFormsModule,
    AdjustPanelHeightDirective,
  ],
  templateUrl: './select.component.html',
  styleUrl: './select.component.scss',
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: SelectComponent,
      multi: true
    }
  ]
})

export class SelectComponent implements ControlValueAccessor {

  @ViewChildren('optionElement') optionElements!: QueryList<ElementRef<HTMLSpanElement>>;

  @Input()
  set disabled(value: boolean) {
    this._disabled = value;
    if (value) {
      this.formControl.disable();
    } else {
      this.formControl.enable();
    }
  }
  get disabled(): boolean {
    return this._disabled;
  }
	@Input() mode: ESelectMode = ESelectMode.LIGHT;
  @Input() errorMessages: { [key: string]: string } = {};
  @Input() hint = '';
  @Input() label = '';
  @Input() options: ISelectOption[] = [];
  @Input() placeholder = '';
  @Input() required = false;
  @Input({ transform: booleanAttribute }) multiple = false;
  @Input({ transform: booleanAttribute }) hideAssistiveText = false;
  @Input()
  set validators(validatorFns: ValidatorFn[]) {
    const validators = [...validatorFns];
    if (this.required) {
      validators.push(Validators.required);
    }
    this.formControl.setValidators(validators);
    this.formControl.updateValueAndValidity();
  }

  @Output() selectionChange = new EventEmitter<MatSelectChange>();

  private _disabled = false;
  formControl = new FormControl('');
  onChange: any = () => {};
  onTouch: any = () => {};
  value!: string;

  /**
   * Computed signal returning the CSS classes for the select panel.
   * Ensures base and mode classes are always applied, avoiding race conditions in Firefox.
   */
  panelClass = computed(() => ['admin-select-panel', this.mode]);

	/**
   * Map that stores the tooltip disabled state for each select option.
   * The key is the index of the option and the value is a boolean indicating whether the tooltip is disabled.
   */
	tooltipDisabledMap: Map<number, boolean> = new Map();

  // begin: methods for ControlValueAccessor implementation
  registerOnChange(fn: any): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: any): void {
    this.onTouch = fn;
  }

  writeValue(value: any): void {
    this.value = value;
    this.formControl.setValue(value, { emitEvent: false });
  }

  getErrorMessage(): string {
    const errors = this.formControl.errors;
    if (errors) {
      const firstError = Object.keys(errors)[0];
      return this.errorMessages[firstError] || '';
    }
    return '';
  }

  hasError(): boolean {
    return this.formControl.touched && this.formControl.invalid;
  }

  onClosed(): void {
    this.onTouch();
  }

  onBlur(): void {
    this.onTouch();
  }

  onSelectionChange(event: any): void {
    this.value = event.value;
    this.onChange(this.value);
    this.onTouch();
    this.selectionChange.emit(event);
  }
  // end: methods for ControlValueAccessor implementation

	/**
   * Method executed when the select panel is opened.
   * Checks for overflow in the select options after a short delay.
   * This is used to determine whether a tooltip should be shown or not.
   */
	onOpened(): void {
    setTimeout(() => {
      this.checkOverflow();
    }, 100);
  }

	/**
   * Method that checks for overflow in the select options.
   * This is used to determine whether a tooltip should be shown or not.
   */
	checkOverflow() {
		if (this.optionElements) {
			this.optionElements.forEach((optionElement, index) => {
				const element = optionElement.nativeElement;
				this.tooltipDisabledMap.set(index, element.scrollWidth <= element.clientWidth);
			});
		}
	}

	/**
   * Method that checks if the tooltip should be disabled for a given option.
   * This is used to determine whether a tooltip should be shown or not.
   */
  isTooltipDisabled(index: number): boolean {
    return this.tooltipDisabledMap.get(index) || false;
  }
}
