import { ApplicationRef, InjectionToken, inject } from '@angular/core';

export const ROOT_ELEMENT = new InjectionToken<Promise<HTMLElement>>(
	'Application root element',
	{
		providedIn: 'root',
		factory: () => {
			const appRef = inject(ApplicationRef);
			return (async () => {
				const root = await getRootElement(appRef);
				return root;
			})();
		}
	}
);

async function getRootElement(appRef: ApplicationRef, wait: number = 50, tries: number = 5) {
	if (tries <= 0) { throw new Error('Cannot get root element'); }
	await sleep(wait);
	const root: HTMLElement = appRef.components[0]?.location?.nativeElement;
	if (root) { return root; }
	return getRootElement(appRef, tries - 1);
}

function sleep(ms: number) {
	return new Promise<void>((resolve) => setTimeout(() => {
		resolve(undefined);
	}, ms));
}
