export function isFocusable(element?: Node) {
	if (!element) {
		return false;
	}

	if ((element as unknown as { disabled: boolean }).disabled) {
		return false;
	}

	switch (element.nodeName) {
		case 'A':
			return (
				!!(element as HTMLLinkElement).href &&
				(element as HTMLLinkElement).rel !== 'ignore'
			);
		case 'INPUT':
			return (element as HTMLInputElement).type !== 'hidden';
		case 'BUTTON':
		case 'SELECT':
		case 'TEXTAREA':
			return true;
		default:
			if (typeof (element as HTMLElement).getAttribute !== 'function') {
				return false;
			}
			return (
				(element as HTMLElement).getAttribute('tabindex') &&
				Number((element as HTMLElement).getAttribute('tabindex')) >= 0
			);
	}
}
