import { NgClass } from '@angular/common';
import { Component, EventEmitter, Input, Output } from '@angular/core';

export interface IAdminSlideTextToggleOption {
  id: string;
  text: string;
  disabled?: boolean;
  active?: boolean;
}

export enum EAdminSlideTextToggleMode {
  LIGHT = 'light',
  DARK = 'dark'
}

@Component({
  selector: 'admin-slide-text-toggle',
  standalone: true,
  imports: [
    NgClass
  ],
  templateUrl: './slide-text-toggle.component.html',
  styleUrl: './slide-text-toggle.component.scss'
})
export class SlideTextToggleComponent {
  @Input() options: IAdminSlideTextToggleOption[] = [];
  @Input() mode = EAdminSlideTextToggleMode.LIGHT;

  @Output() buttonClicked = new EventEmitter<IAdminSlideTextToggleOption>();

  optionSlideTextToggleClicked(option: IAdminSlideTextToggleOption): void {
    // Emite el evento con la opción activa
    this.buttonClicked.emit(option);
  }

}
