import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, OnInit, Output, ViewEncapsulation, booleanAttribute } from '@angular/core';
import { FormControl, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { NgxColorsColor, NgxColorsModule, validColorValidator } from 'ngx-colors';

export enum EColorPickerMode {
  LIGHT = 'light',
  DARK = 'dark'
}
@Component({
  selector: 'admin-color-picker',
  standalone: true,
  imports: [
		CommonModule,
		FormsModule, 
		ReactiveFormsModule, 
		NgxColorsModule, 
		MatFormFieldModule, 
		MatInputModule,
	],
  encapsulation: ViewEncapsulation.None,
  templateUrl: './color-picker.component.html',
  styleUrl: './color-picker.component.scss',
  providers: []
})
export class ColorPickerComponent implements OnInit {

	@Input() acceptLabel: string = 'Accept';
	@Input() cancelLabel: string = 'Cancel';
  @Input() color: string | null = null;
	@Input() errorMessages!: Record<string, string>;
  @Input() hideColorPicker: boolean = false;
  @Input() hideTextInput: boolean = false;
	@Input() label = 'Color';
	@Input() mode: EColorPickerMode = EColorPickerMode.LIGHT;
  @Input() palette?: NgxColorsColor[] | string[];
	@Input() placeholder = '';
  @Input({ transform: booleanAttribute }) readonly: boolean = false;
  @Input({ transform: booleanAttribute }) required: boolean = false;

  @Output() change = new EventEmitter<string>();
  @Output() close = new EventEmitter<void>();
  @Output() input = new EventEmitter<string>();
  @Output() open = new EventEmitter<void>();
  @Output() slider = new EventEmitter<string>();

	inputCtrl = new FormControl(this.color);
  pickerCtrl = new FormControl(this.color);

  get displayColor(): string | null {
    return this.color || null;
  }

  onColorPickerPanelChange(color: any): void {
    this.change.emit(color);
  }

  onColorPickerPanelInput(color: any): void {
    this.input.emit(color);
  }

  onColorPickerPanelSlider(color: string): void {
    this.slider.emit(color);
  }

  onColorPickerPanelOpen(): void {
    this.open.emit();
  }

  onColorPickerPanelClose(): void {
    this.close.emit();
  }

	ngOnInit(): void {
    // Configurar validadores para el input de texto
    const inputValidators = [validColorValidator()];
    if (this.required) {
      inputValidators.push(Validators.required);
    }
    
    // Configurar validadores para el picker (solo required si aplica)
    const pickerValidators = [];
    if (this.required) {
      pickerValidators.push(Validators.required);
    }
    
    this.inputCtrl.setValidators(inputValidators);
    this.pickerCtrl.setValidators(pickerValidators);
    
    // Actualizar la validación después de establecer los validadores
    this.inputCtrl.updateValueAndValidity();
    this.pickerCtrl.updateValueAndValidity();

    this.inputCtrl.setValue(this.color);
    this.pickerCtrl.setValue(this.color);

    this.inputCtrl.valueChanges.subscribe((color) => {
      if (color && this.inputCtrl.valid) {
        // Si el valor es válido, sincronizar con el picker
        this.pickerCtrl.setValue(color, {
          emitEvent: false,
        });
      } else {
        // Si el valor es inválido o vacío, limpiar el picker
        this.pickerCtrl.setValue(null, {
          emitEvent: false,
        });
      }
    });

    this.pickerCtrl.valueChanges.subscribe((color) => {
      if (color) {
        // El picker siempre maneja colores válidos, sincronizar con el input
        this.inputCtrl.setValue(color, {
          emitEvent: false,
        });
      } else {
        // Si el picker se limpia (null), limpiar también el input
        this.inputCtrl.setValue('', {
          emitEvent: false,
        });
      }
    });
  }
}