import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { ImgEntityType } from '../../atoms/image/image.component';

export enum EConversationalStarterButtonMode {
	LIGHT = 'light',
	DARK = 'dark'
}

export enum EConversationalStarterButtonType {
	BUTTON = 'button',
	SUBMIT = 'submit',
	RESET = 'reset'
}

@Component({
	selector: 'admin-conversational-starter-button',
	standalone: true,
	imports: [
		CommonModule,
		MatButtonModule,
		MatTooltipModule,
		MatIconModule,
		IconComponent
	],
	templateUrl: './conversational-starter-button.component.html',
	styleUrl: './conversational-starter-button.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class ConversationalStarterButtonComponent {
	@Input() mode: EConversationalStarterButtonMode = EConversationalStarterButtonMode.LIGHT;
	@Input() id: string = '';
	@Input() image?: string;
	@Input() imageAlt?: string;
	@Input() title?: string;
	@Input() text: string = '';
	@Input() textTooltip: string = '';
	@Input() type = EConversationalStarterButtonType.BUTTON;
	@Input() disabled: boolean = false;

	imgError = false;
	ImgEntityType = ImgEntityType;
	EIconName = EIconName;

	@Output() buttonClicked = new EventEmitter<Event>();

	handleImageError() {
		this.imgError = !this.imgError;
	}

	handleClick() {
		this.buttonClicked.emit();
	}
}