import { ComponentType } from '@angular/cdk/overlay';
import { ComponentRef, Injectable, Injector } from '@angular/core';
import { SidenavService } from './sidenav.service';

@Injectable({
	providedIn: 'root'
})
export class GlobalPanelService {

	constructor(
		protected sidenavService: SidenavService,
		protected injector: Injector
	) { }

	open(comp: ComponentType<any>, data?: Object): ComponentRef<any> {
		const dataInject: Injector = this.sidenavService.createData(
			!!data ? data : {}
		);

		const compRef = this.sidenavService.attachComponent(comp, dataInject);

		this.sidenavService.open();

		return compRef;
	}

	close() {
		this.sidenavService.close();
	}

}
