import { CommonModule } from '@angular/common';
import { booleanAttribute, Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { FormControl, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { MatChipsModule } from '@angular/material/chips';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatTooltipModule } from '@angular/material/tooltip';
import { ButtonComponent, EButtonButtonType, EButtonMode } from '../../../public-api';
import { EIconColor, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EChipGroupMode, EChipGroupTheme, EChipGroupType, IAdminChipGroup } from '../types/chip-group.types';

@Component({
  selector: 'admin-chip-group-browser',
  templateUrl: 'chip-group-browser.component.html',
  styleUrl: 'chip-group-browser.component.scss',
  standalone: true,
  host:{'class': 'admin-chip-group-browser'},
  encapsulation: ViewEncapsulation.None,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatChipsModule,
    MatIconModule,
    MatInputModule,
    MatTooltipModule,
    IconComponent,
    ButtonComponent
  ],
})
export class ChipGroupBrowserComponent {

  @Input() chips: (IAdminChipGroup)[] = [];
  @Input() buttonDisabled!: boolean;
  @Input() buttonText!: string;
  @Input() buttonTooltip!: string;
  @Input() chipGroupBrowserControl: FormControl = new FormControl();
  @Input() errorMessages!: {[key:string]: string | boolean};
  @Input() hint!:string;
  @Input() label!: string;
	@Input() mode: EChipGroupMode = EChipGroupMode.LIGHT;
	@Input({ transform: booleanAttribute }) hideAssistiveText = false;

  @Output() removedChip = new EventEmitter<IAdminChipGroup>();
  @Output() clickedChip = new EventEmitter<IAdminChipGroup>();
  @Output() clickedButton = new EventEmitter<Event>();

  buttonButtonTypeDefault = EButtonButtonType.MATFLATBUTTON;

	EButtonMode = EButtonMode;
	EChipGroupMode = EChipGroupMode;
	EChipGroupTheme = EChipGroupTheme;
	EIconName = EIconName;
	EIconColor = EIconColor;

	typeOptions = [
		{
			type: EChipGroupType.ELEARNING,
			icon: EIconName.SCHOOL,
		},
		{
			type: EChipGroupType.IMAGE,
			icon: EIconName.IMAGE,
		},
		{
			type: EChipGroupType.AUDIO,
			icon: EIconName.HEADPHONES,
		},
		{
			type: EChipGroupType.DOC,
			icon: EIconName.DESCRIPTION,
		},
		{
			type: EChipGroupType.PDF,
			icon: EIconName.CUSTOM_PDF,
		},
		{
			type: EChipGroupType.ZIP,
			icon: EIconName.FOLDER_ZIP,
		},
		{
			type: EChipGroupType.VIDEO,
			icon: EIconName.ONDEMAND_VIDEO,
		},
	];

	ngOnChanges() {
		this.chips.forEach(chip => {
			const typeDetail = this.typeOptions.find(option => option.type === chip.type);
			if (typeDetail) {
				chip.iconName = typeDetail.icon as EIconName;
			}

		});
	}

}
