import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, effect, input } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { CropperPosition, Dimensions, ImageCroppedEvent, ImageCropperComponent, ImageTransform, LoadedImage } from 'ngx-image-cropper';
import { SliderComponent } from '../../atoms/slider/slider.component';

export enum EImageCropOutputFormat {
	PNG = 'png',
	JPEG = 'jpeg',
	WEBP = 'webp',
	BMP = 'bmp',
	ICO = 'ico',
}

export enum EImageCropOutputType {
	BASE64 = 'base64',
	BLOB = 'blob'
}
@Component({
  selector: 'admin-image-crop',
  standalone: true,
  imports: [CommonModule, ImageCropperComponent, FormsModule, SliderComponent],
  templateUrl: './image-crop.component.html',
  styleUrl: './image-crop.component.scss'
})
export class ImageCropComponent {
	
	transform: ImageTransform = {
		translateUnit: 'px',
		scale: 1,
		rotate: 0,
		flipH: false,
		flipV: false
	};

	@Input({ transform: coerceBooleanProperty }) disabled: boolean = false;
	@Input() imageAltText: string | undefined = undefined;
	@Input() imageBase64: string | undefined = undefined;
	@Input() imageFile: File | undefined = undefined;
	@Input() imageChangedEvent: Event | null = null;
	@Input() imageURL: string | undefined = undefined;
	@Input() cropperWidth = 100;
	@Input() cropperHeight = 100;
	@Input() outputFormat: EImageCropOutputFormat = EImageCropOutputFormat.PNG;
	@Input() outputType: EImageCropOutputType = EImageCropOutputType.BLOB;
	@Input() roundCropper: boolean = false;
	zoomValue = input<number>(1);
	@Input() minZoomValue = 1;		
	@Input() maxZoomValue = 5;
	@Input() stepZoomValue = 0.1;
	@Output() cropperChanged = new EventEmitter<CropperPosition>();
	@Output() cropperReady = new EventEmitter<Dimensions>();
	@Output() imageCropped = new EventEmitter<ImageCroppedEvent>();
	@Output() imageLoaded = new EventEmitter<LoadedImage>();
	@Output() loadImageFailed = new EventEmitter<void>();
	@Output() zoomChangeEvent = new EventEmitter<number>();

	
	private zoomEffect = effect(() => {
		const newZoomValue = this.zoomValue();
		this.transform = {
			...this.transform,
			scale: newZoomValue
		};
	});

	onCropperChanged(event: CropperPosition) {
		this.cropperChanged.emit(event);
	}

	onCropperReady(event: Dimensions) {
		this.cropperReady.emit(event);
	}

	onImageCropped(event: ImageCroppedEvent) {
		this.imageCropped.emit(event);
	}

	onImageLoaded(event: LoadedImage) {
		this.imageLoaded.emit(event);
	}

	onLoadImageFailed() {
		this.loadImageFailed.emit();
	}

	onZoomChange(event: number): void {
		this.transform = {
			...this.transform,
			scale: event
		};
		this.zoomChangeEvent.emit(event);
	}

}
