import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output, ViewEncapsulation } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule } from '@angular/material/menu';
import { MatTooltipModule } from '@angular/material/tooltip';
import { DividerComponent, EDividerMode } from '../../atoms/divider/divider.component';
import { EIconMode, EIconName, IconComponent } from '../../atoms/icon/icon.component';
import { EImgMode, ImageComponent, ImgEntityType } from '../../atoms/image/image.component';
import { ButtonComponent, EButtonButtonType, EButtonColor, EButtonMode, EButtonType } from '../button/button.component';

// Propiedades comunes reutilizables
interface IAdminProfileMenuCommonProps {
	idOption?: string;
	text?: string;
	disabledOption?: boolean;
	hasIntro?: boolean;
	intro?: string;
	type?: string;
	action?: () => void;
}

// Caso con icono (iconFontFamily obligatorio)
interface IAdminProfileMenuWithIcon extends IAdminProfileMenuCommonProps {
	icon: EIconName;
}

// Caso sin icono (iconFontFamily no permitida)
interface IAdminProfileMenuWithoutIcon extends IAdminProfileMenuCommonProps {
	icon?: undefined;
}

// Interface para la opción de menu
export type IAdminProfileMenuOption = IAdminProfileMenuWithIcon | IAdminProfileMenuWithoutIcon;

export enum EAdminProfileMenuMode {
	LIGHT = 'light',
	DARK = 'dark'
}

@Component({
	selector: 'admin-profile-menu',
	standalone: true,
	imports: [
		CommonModule,
		MatButtonModule,
		MatTooltipModule,
		MatMenuModule,
		ButtonComponent,
		DividerComponent,
		MatIconModule,
		IconComponent,
		ImageComponent
	],
	templateUrl: './profile-menu.component.html',
	styleUrl: './profile-menu.component.scss',
	encapsulation: ViewEncapsulation.None
})
export class ProfileMenuComponent {

	@Input() mode = EAdminProfileMenuMode.LIGHT;
	@Input() menuButtonId?: string;
	@Input() menuButtonDisabled: boolean = false;
	@Input() menuButtonTooltip: string = '';
	@Input() id?: string;
	@Input() headerImgUrl = '';
	@Input() headerImgAlt = '';
	@Input() headerTitle = '';
	@Input() headerSubtitle = '';
	@Input() showHeaderButton?: boolean = true;
	@Input() headerButtonText?: string = '';
	@Input() options: IAdminProfileMenuOption[] = [];

	imgError = false;
	ImgEntityType = ImgEntityType;
	ImgMode = EImgMode;

	EAdminProfileMenuMode = EAdminProfileMenuMode;
	EDividerMode = EDividerMode;
	EButtonMode = EButtonMode;

	buttonButtonTypeDefault = EButtonButtonType.MATICONBUTTON;
	buttonColorDefault = EButtonColor.PRIMARY;
	buttonTypeDefault = EButtonType.SUBMIT;

	buttonHeaderButtonTypeDefault = EButtonButtonType.MATSTROKEDBUTTON;
	buttonHeaderColorDefault = EButtonColor.PRIMARY;
	buttonHeaderTypeDefault = EButtonType.SUBMIT;

	EIconMode = EIconMode;
	EIconName = EIconName;

	@Output() menuButtonClicked = new EventEmitter<Event>();
	@Output() headerButtonClicked = new EventEmitter<void>();
	@Output() menuOptionClicked = new EventEmitter<IAdminProfileMenuOption>();

	handleImageError() {
		this.imgError = !this.imgError;
	}

	handleClick() {
		this.menuButtonClicked.emit();
	}

	handleMenuOptionClick(option: IAdminProfileMenuOption) {
		if (option.action) {
			option.action();
		}
		this.menuOptionClicked.emit(option);
	}
}
